1	/**
2	 * UsageNormalizer — maps provider-native usage objects into OracleUsage.
3	 *
4	 * Each provider exposes cache + reasoning tokens under a different field
5	 * name. We normalize once at the adapter boundary so UsageLogger always
6	 * sees the same shape.
7	 *
8	 * The raw provider object is preserved in OracleUsage.rawUsageJson for
9	 * audit and debugging.
10	 */
11	
12	import type { OracleProvider } from '../routes';
13	import type { OracleUsage } from '../client/types';
14	
15	export interface AnthropicUsageRaw {
16	  input_tokens?: number;
17	  output_tokens?: number;
18	  cache_creation_input_tokens?: number;
19	  cache_read_input_tokens?: number;
20	}
21	
22	export interface VertexUsageRaw {
23	  promptTokenCount?: number;
24	  candidatesTokenCount?: number;
25	  cachedContentTokenCount?: number;
26	  thoughtsTokenCount?: number;
27	  totalTokenCount?: number;
28	}
29	
30	export interface OpenAIUsageRaw {
31	  prompt_tokens?: number;
32	  completion_tokens?: number;
33	  prompt_tokens_details?: { cached_tokens?: number };
34	  completion_tokens_details?: { reasoning_tokens?: number };
35	  total_tokens?: number;
36	}
37	
38	export interface NormalizeArgs {
39	  provider: OracleProvider;
40	  raw: unknown;
41	  latencyMs: number;
42	  providerRequestId?: string;
43	}
44	
45	export interface DeepSeekUsageRaw {
46	  prompt_tokens?: number;
47	  completion_tokens?: number;
48	  prompt_cache_hit_tokens?: number;
49	  prompt_cache_miss_tokens?: number;
50	  completion_tokens_details?: { reasoning_tokens?: number };
51	  total_tokens?: number;
52	}
53	
54	/**
55	 * Qwen via DashScope's OpenAI-compat layer can return either the Chat
56	 * Completions usage shape (`prompt_tokens_details.cached_tokens`) or the
57	 * Responses API shape (`input_tokens_details.cached_tokens`), depending on
58	 * which endpoint the adapter used. We accept both.
59	 */
60	export interface QwenUsageRaw {
61	  prompt_tokens?: number;
62	  completion_tokens?: number;
63	  prompt_tokens_details?: { cached_tokens?: number };
64	  input_tokens?: number;
65	  output_tokens?: number;
66	  input_tokens_details?: { cached_tokens?: number };
67	  output_tokens_details?: { reasoning_tokens?: number };
68	  total_tokens?: number;
69	}
70	
71	export function normalizeUsage(args: NormalizeArgs): OracleUsage {
72	  const { provider, raw, latencyMs, providerRequestId } = args;
73	  switch (provider) {
74	    case 'anthropic':
75	      return normalizeAnthropic(raw as AnthropicUsageRaw, latencyMs, providerRequestId);
76	    case 'vertex':
77	      return normalizeVertex(raw as VertexUsageRaw, latencyMs, providerRequestId);
78	    case 'google':
79	      return normalizeVertex(raw as VertexUsageRaw, latencyMs, providerRequestId);
80	    case 'openai':
81	      return normalizeOpenAI(raw as OpenAIUsageRaw, latencyMs, providerRequestId);
82	    case 'deepseek':
83	      return normalizeDeepSeek(raw as DeepSeekUsageRaw, latencyMs, providerRequestId);
84	    case 'qwen':
85	      return normalizeQwen(raw as QwenUsageRaw, latencyMs, providerRequestId);
86	    default:
87	      throw new Error(`normalizeUsage: unhandled provider "${provider as string}"`);
88	  }
89	}
90	
91	function normalizeAnthropic(
92	  raw: AnthropicUsageRaw,
93	  latencyMs: number,
94	  providerRequestId?: string,
95	): OracleUsage {
96	  return {
97	    inputTokens: raw.input_tokens,
98	    outputTokens: raw.output_tokens,
99	    cachedInputTokens: raw.cache_read_input_tokens,
100	    cacheWriteTokens: raw.cache_creation_input_tokens,
101	    latencyMs,
102	    providerRequestId,
103	    rawUsageJson: raw,
104	  };
105	}
106	
107	function normalizeVertex(
108	  raw: VertexUsageRaw,
109	  latencyMs: number,
110	  providerRequestId?: string,
111	): OracleUsage {
112	  return {
113	    inputTokens: raw.promptTokenCount,
114	    outputTokens: raw.candidatesTokenCount,
115	    cachedInputTokens: raw.cachedContentTokenCount,
116	    reasoningTokens: raw.thoughtsTokenCount,
117	    latencyMs,
118	    providerRequestId,
119	    rawUsageJson: raw,
120	  };
121	}
122	
123	function normalizeOpenAI(
124	  raw: OpenAIUsageRaw,
125	  latencyMs: number,
126	  providerRequestId?: string,
127	): OracleUsage {
128	  return {
129	    inputTokens: raw.prompt_tokens,
130	    outputTokens: raw.completion_tokens,
131	    cachedInputTokens: raw.prompt_tokens_details?.cached_tokens,
132	    reasoningTokens: raw.completion_tokens_details?.reasoning_tokens,
133	    latencyMs,
134	    providerRequestId,
135	    rawUsageJson: raw,
136	  };
137	}
138	
139	/**
140	 * Qwen/DashScope: handle BOTH the Chat (`prompt_tokens`/`prompt_tokens_details`)
141	 * and Responses (`input_tokens`/`input_tokens_details`) usage shapes.
142	 */
143	function normalizeQwen(
144	  raw: QwenUsageRaw,
145	  latencyMs: number,
146	  providerRequestId?: string,
147	): OracleUsage {
148	  return {
149	    inputTokens: raw.prompt_tokens ?? raw.input_tokens,
150	    outputTokens: raw.completion_tokens ?? raw.output_tokens,
151	    cachedInputTokens:
152	      raw.prompt_tokens_details?.cached_tokens ??
153	      raw.input_tokens_details?.cached_tokens,
154	    reasoningTokens: raw.output_tokens_details?.reasoning_tokens,
155	    latencyMs,
156	    providerRequestId,
157	    rawUsageJson: raw,
158	  };
159	}
160	
161	/** DeepSeek surfaces cache hits/misses in dedicated top-level fields. */
162	function normalizeDeepSeek(
163	  raw: DeepSeekUsageRaw,
164	  latencyMs: number,
165	  providerRequestId?: string,
166	): OracleUsage {
167	  return {
168	    inputTokens: raw.prompt_tokens,
169	    outputTokens: raw.completion_tokens,
170	    cachedInputTokens: raw.prompt_cache_hit_tokens,
171	    reasoningTokens: raw.completion_tokens_details?.reasoning_tokens,
172	    latencyMs,
173	    providerRequestId,
174	    rawUsageJson: raw,
175	  };
176	}
177

1	/**
2	 * StructuredOutputValidator — runs a Zod schema check over a model's
3	 * structured output. Returns a discriminated result so the caller can
4	 * decide whether to escalate to a repair route.
5	 *
6	 * This validator is deterministic. It must not call an LLM.
7	 */
8	
9	import type { ZodType, ZodError } from 'zod';
10	
11	export type ValidationResult<T> =
12	  | { ok: true; value: T }
13	  | { ok: false; error: ZodError; receivedJson: unknown };
14	
15	export class StructuredOutputValidator {
16	  validate<T>(schema: ZodType<T>, candidate: unknown): ValidationResult<T> {
17	    const parsed = schema.safeParse(candidate);
18	    if (parsed.success) return { ok: true, value: parsed.data };
19	    return { ok: false, error: parsed.error, receivedJson: candidate };
20	  }
21	}
22	
23	let cached: StructuredOutputValidator | null = null;
24	export function getStructuredOutputValidator(): StructuredOutputValidator {
25	  if (!cached) cached = new StructuredOutputValidator();
26	  return cached;
27	}
