1	/**
2	 * EvidenceValidator — deterministic verification that a model-proposed
3	 * `exactQuote` physically exists in its claimed source text.
4	 *
5	 * This is the binary provenance check from
6	 * docs/oracle/03-candidate-before-claim-validation.md "Provenance vs.
7	 * Corroboration". If this fails, the candidate must be destroyed.
8	 *
9	 * R2 ships the core logic (.includes + offsets, single-source). The full
10	 * spec (normalization policy, edited-message rejection, multi-line
11	 * boundaries) lands in R5 (claim extraction worker) where the full
12	 * candidate-before-claim pipeline is wired up.
13	 */
14	
15	export type QuoteValidationVerdict =
16	  | 'exact_match'
17	  | 'normalized_match'
18	  | 'failed'
19	  | 'ambiguous';
20	
21	export interface QuoteValidationResult {
22	  verdict: QuoteValidationVerdict;
23	  validatedExactQuote?: string;
24	  validatedCharStart?: number;
25	  validatedCharEnd?: number;
26	  validationMethod: 'verbatim_includes' | 'verbatim_offset_match' | 'none';
27	  detail: string;
28	}
29	
30	export interface ValidateQuoteArgs {
31	  /** The source text the model claims to be quoting from. */
32	  sourceText: string;
33	  /** The quote the model produced. */
34	  exactQuoteProvided: string;
35	  /** Optional char offsets the model provided. */
36	  charStartProvided?: number;
37	  charEndProvided?: number;
38	}
39	
40	export class EvidenceValidator {
41	  validateQuote(args: ValidateQuoteArgs): QuoteValidationResult {
42	    const { sourceText, exactQuoteProvided, charStartProvided, charEndProvided } = args;
43	
44	    if (!exactQuoteProvided || exactQuoteProvided.length === 0) {
45	      return {
46	        verdict: 'failed',
47	        validationMethod: 'none',
48	        detail: 'exactQuoteProvided is empty.',
49	      };
50	    }
51	
52	    // If offsets were given, prefer them. They must match exactly.
53	    // Require BOTH offsets together (reject if exactly one is provided), and
54	    // validate offset sanity before slicing — mirrors the stricter checks in
55	    // packages/oracle-engines/src/extraction/quote-validator.ts.
56	    const hasStart = typeof charStartProvided === 'number';
57	    const hasEnd = typeof charEndProvided === 'number';
58	    if (hasStart !== hasEnd) {
59	      return {
60	        verdict: 'failed',
61	        validationMethod: 'none',
62	        detail: 'charStartProvided and charEndProvided must be supplied together or not at all.',
63	      };
64	    }
65	    if (hasStart && hasEnd) {
66	      if (charStartProvided! < 0 || charStartProvided! > charEndProvided! || charEndProvided! > sourceText.length) {
67	        return {
68	          verdict: 'failed',
69	          validationMethod: 'verbatim_offset_match',
70	          detail: `Provided offsets [${charStartProvided}, ${charEndProvided}] are out of range for sourceText (length ${sourceText.length}).`,
71	        };
72	      }
73	      const slice = sourceText.slice(charStartProvided, charEndProvided);
74	      if (slice === exactQuoteProvided) {
75	        return {
76	          verdict: 'exact_match',
77	          validatedExactQuote: slice,
78	          validatedCharStart: charStartProvided,
79	          validatedCharEnd: charEndProvided,
80	          validationMethod: 'verbatim_offset_match',
81	          detail: 'Quote matched exactly at provided offsets.',
82	        };
83	      }
84	      return {
85	        verdict: 'failed',
86	        validationMethod: 'verbatim_offset_match',
87	        detail: `Source text at offsets [${charStartProvided}, ${charEndProvided}] does not equal exactQuoteProvided.`,
88	      };
89	    }
90	
91	    // No offsets — scan for the quote.
92	    const firstIdx = sourceText.indexOf(exactQuoteProvided);
93	    if (firstIdx === -1) {
94	      return {
95	        verdict: 'failed',
96	        validationMethod: 'verbatim_includes',
97	        detail: 'exactQuoteProvided was not found in sourceText.',
98	      };
99	    }
100	    // Ambiguity check: if the quote appears more than once we cannot be sure
101	    // which occurrence is the source. Reject unless the model provides offsets.
102	    const secondIdx = sourceText.indexOf(exactQuoteProvided, firstIdx + 1);
103	    if (secondIdx !== -1) {
104	      return {
105	        verdict: 'ambiguous',
106	        validationMethod: 'verbatim_includes',
107	        detail: 'Quote appears more than once in sourceText. Model must provide explicit offsets.',
108	      };
109	    }
110	    return {
111	      verdict: 'exact_match',
112	      validatedExactQuote: exactQuoteProvided,
113	      validatedCharStart: firstIdx,
114	      validatedCharEnd: firstIdx + exactQuoteProvided.length,
115	      validationMethod: 'verbatim_includes',
116	      detail: 'Quote matched exactly via single-occurrence includes() scan.',
117	    };
118	  }
119	}
120	
121	let cached: EvidenceValidator | null = null;
122	export function getEvidenceValidator(): EvidenceValidator {
123	  if (!cached) cached = new EvidenceValidator();
124	  return cached;
125	}
