1	// Embeddings.
2	//
3	// Spec uses vector(1536) — the OpenAI text-embedding-3-small dimension.
4	// OpenRouter doesn't host that exact model, so:
5	//
6	//   1. If OPENAI_API_KEY is set, call OpenAI directly for text-embedding-3-small.
7	//   2. Otherwise, return a deterministic-zero vector (length 1536) so the rest
8	//      of the system can be exercised without breaking the column type.
9	//
10	// See DECISIONS.md D3.embeddings — do NOT silently swap the vector dimension.
11	
12	import { EMBEDDING_DIM } from '@oracle/shared';
13	
14	const OPENAI_EMBEDDING_URL = 'https://api.openai.com/v1/embeddings';
15	const MODEL = 'text-embedding-3-small';
16	/** Max inputs per embeddings request before we split into multiple calls. */
17	const MAX_BATCH = 256;
18	
19	type EmbeddingResponse = {
20	  data: Array<{ index: number; embedding: number[] }>;
21	};
22	
23	/**
24	 * Embed a single string. Returns a vector of length EMBEDDING_DIM.
25	 * Falls back to a zero vector if OPENAI_API_KEY isn't set.
26	 */
27	export async function embedText(text: string): Promise<{
28	  vector: number[];
29	  model: string;
30	  fallback: boolean;
31	}> {
32	  const apiKey = process.env.OPENAI_API_KEY;
33	  if (!apiKey) {
34	    return { vector: new Array(EMBEDDING_DIM).fill(0), model: 'zero-stub', fallback: true };
35	  }
36	
37	  const res = await fetch(OPENAI_EMBEDDING_URL, {
38	    method: 'POST',
39	    headers: {
40	      'Content-Type': 'application/json',
41	      Authorization: `Bearer ${apiKey}`,
42	    },
43	    body: JSON.stringify({ model: MODEL, input: text }),
44	  });
45	
46	  if (!res.ok) {
47	    throw new Error(`OpenAI embeddings call failed: ${res.status} ${await res.text()}`);
48	  }
49	  const body = (await res.json()) as EmbeddingResponse;
50	  const vector = body.data[0]?.embedding;
51	  if (!vector || vector.length !== EMBEDDING_DIM) {
52	    throw new Error(
53	      `OpenAI returned unexpected embedding length: ${vector?.length}. ` +
54	        `Spec locks vector(${EMBEDDING_DIM}).`,
55	    );
56	  }
57	  return { vector, model: MODEL, fallback: false };
58	}
59	
60	export async function embedMany(texts: string[]): Promise<{
61	  vectors: number[][];
62	  model: string;
63	  fallback: boolean;
64	}> {
65	  const apiKey = process.env.OPENAI_API_KEY;
66	  if (!apiKey) {
67	    return {
68	      vectors: texts.map(() => new Array(EMBEDDING_DIM).fill(0)),
69	      model: 'zero-stub',
70	      fallback: true,
71	    };
72	  }
73	  const vectors: number[][] = [];
74	  // The embeddings endpoint caps inputs per request; split into safe chunks
75	  // and concatenate results in order.
76	  for (let start = 0; start < texts.length; start += MAX_BATCH) {
77	    const chunk = texts.slice(start, start + MAX_BATCH);
78	    const res = await fetch(OPENAI_EMBEDDING_URL, {
79	      method: 'POST',
80	      headers: {
81	        'Content-Type': 'application/json',
82	        Authorization: `Bearer ${apiKey}`,
83	      },
84	      body: JSON.stringify({ model: MODEL, input: chunk }),
85	    });
86	    if (!res.ok) {
87	      throw new Error(`OpenAI embeddings call failed: ${res.status} ${await res.text()}`);
88	    }
89	    const body = (await res.json()) as EmbeddingResponse;
90	    // The API does not guarantee response order — sort by `index` ascending.
91	    const sorted = [...body.data].sort((a, b) => a.index - b.index);
92	    if (sorted.length !== chunk.length) {
93	      throw new Error(
94	        `OpenAI returned ${sorted.length} embeddings for ${chunk.length} inputs.`,
95	      );
96	    }
97	    for (const d of sorted) {
98	      if (!d.embedding || d.embedding.length !== EMBEDDING_DIM) {
99	        throw new Error(
100	          `OpenAI returned unexpected embedding length: ${d.embedding?.length}. ` +
101	            `Spec locks vector(${EMBEDDING_DIM}).`,
102	        );
103	      }
104	      vectors.push(d.embedding);
105	    }
106	  }
107	  return {
108	    vectors,
109	    model: MODEL,
110	    fallback: false,
111	  };
112	}
