1	/**
2	 * AnthropicAdapter — direct Anthropic API integration via `@anthropic-ai/sdk`.
3	 *
4	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
5	 * - Calls Anthropic's REST API directly using Anthropic's official SDK.
6	 * - NO Vercel AI SDK and NO OpenRouter in this path.
7	 * - Authenticates via `ANTHROPIC_API_KEY` env var (the SDK auto-reads it).
8	 *
9	 * Caching strategy (round 1 — automatic prefix caching):
10	 * - Anthropic's prompt cache is opt-in per-block via `cache_control: { type:
11	 *   'ephemeral' }`. Round 1 marks the assembled stable system prompt as
12	 *   cacheable so repeated calls hit a read.
13	 * - Cache writes land in `usage.cache_creation_input_tokens`; cache reads in
14	 *   `usage.cache_read_input_tokens`. Both normalize into OracleUsage.
15	 * - Explicit-cache-breakpoint strategies (multiple markers across tools,
16	 *   schema, and semi-stable context) are a round-2 follow-up.
17	 *
18	 * Structured output:
19	 * - Uses Anthropic's native tool-calling mode with a forced single tool
20	 *   choice. The tool's `input_schema` is the standard JSON Schema produced
21	 *   from the caller's Zod schema. Anthropic enforces the schema on the
22	 *   model's tool call.
23	 *
24	 * Per docs/oracle/02-provider-native-ai-architecture.md → "Anthropic direct".
25	 */
26	
27	import Anthropic from '@anthropic-ai/sdk';
28	import type { Message, MessageCreateParamsNonStreaming } from '@anthropic-ai/sdk/resources/messages';
29	import type { MessageBatchIndividualResponse } from '@anthropic-ai/sdk/resources/messages/batches';
30	import type {
31	  OracleObjectResult,
32	  OracleTextResult,
33	  OracleUsage,
34	} from '../client/types';
35	import type { OracleModelRoute, ReasoningEffort } from '../routes';
36	import type {
37	  BatchResultItem,
38	  BatchStatus,
39	  GenerateObjectArgs,
40	  GenerateTextArgs,
41	  OracleProviderAdapter,
42	  RetrieveBatchArgs,
43	  RetrieveBatchResult,
44	  SubmitBatchArgs,
45	  SubmitBatchResult,
46	} from './types';
47	import {
48	  estimatePlanStableTokens,
49	  getCacheHints,
50	  markLastTextPartCacheable,
51	  normalizeMessageContentArray,
52	  pickAnthropicCacheTtl,
53	  shouldDisableCache,
54	  toAnthropicImageContent,
55	} from './cache-utils';
56	import { flattenPlan, tryZodParse, zodToJsonSchema } from './vertex-gemini-adapter';
57	
58	export interface AnthropicAdapterOptions {
59	  /** API key. Defaults to env ANTHROPIC_API_KEY. */
60	  apiKey?: string;
61	  /** Mark the stable system prompt as cache_control: ephemeral. Default true. */
62	  enableSystemPromptCache?: boolean;
63	  /** Max output tokens for both generateText and generateObject. */
64	  defaultMaxTokens?: number;
65	}
66	
67	const DEFAULT_MAX_TOKENS = 4096;
68	const ANTHROPIC_SONNET_CACHE_MIN_TOKENS = 1024;
69	const ANTHROPIC_HAIKU_CACHE_MIN_TOKENS = 2048;
70	
71	export class AnthropicAdapter implements OracleProviderAdapter {
72	  readonly provider = 'anthropic' as const;
73	  private readonly client: Anthropic;
74	  private readonly enableSystemPromptCache: boolean;
75	  private readonly defaultMaxTokens: number;
76	
77	  constructor(opts: AnthropicAdapterOptions = {}) {
78	    const apiKey = opts.apiKey ?? process.env.ANTHROPIC_API_KEY;
79	    if (!apiKey) {
80	      throw new Error(
81	        'AnthropicAdapter: ANTHROPIC_API_KEY is not set. ' +
82	          'Set it in .env.local or pass {apiKey} explicitly.',
83	      );
84	    }
85	    this.client = new Anthropic({ apiKey });
86	    this.enableSystemPromptCache = opts.enableSystemPromptCache ?? true;
87	    this.defaultMaxTokens = opts.defaultMaxTokens ?? DEFAULT_MAX_TOKENS;
88	  }
89	
90	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
91	    const { plan, route, providerOptions } = args;
92	    const { systemPrompt, userMessage } = flattenPlan(plan);
93	    const callStartedAt = Date.now();
94	
95	    const ttl = pickAnthropicCacheTtl(plan.taskType, providerOptions);
96	    const messages = this.buildMessages(plan, userMessage, providerOptions, ttl);
97	    // Caller may raise the output cap (e.g. the image-vision pass); thinking
98	    // budget is carved from the effective max, so compute it first.
99	    const effectiveMaxTokens =
100	      typeof providerOptions?.maxOutputTokens === 'number'
101	        ? providerOptions.maxOutputTokens
102	        : this.defaultMaxTokens;
103	    const thinking = thinkingParam(route.reasoningEffort, effectiveMaxTokens);
104	    const response = await this.client.messages.create({
105	      model: route.modelId,
106	      max_tokens: effectiveMaxTokens,
107	      // Anthropic requires temperature=1 when thinking is enabled.
108	      temperature: thinking
109	        ? 1
110	        : (typeof providerOptions?.temperature === 'number'
111	          ? providerOptions.temperature
112	          : undefined),
113	      system: this.buildSystem(plan, systemPrompt, providerOptions, ttl),
114	      messages,
115	      ...(thinking ? { thinking } : {}),
116	    });
117	    const latencyMs = Date.now() - callStartedAt;
118	    return {
119	      text: this.extractText(response),
120	      usage: this.normalizeUsage(response, latencyMs),
121	      rawResponse: response,
122	    };
123	  }
124	
125	  async generateObject<TSchema, TOutput>(
126	    args: GenerateObjectArgs<TSchema>,
127	  ): Promise<OracleObjectResult<TOutput>> {
128	    const { plan, route, schema, providerOptions } = args;
129	    const { systemPrompt, userMessage } = flattenPlan(plan);
130	    const jsonSchema = zodToJsonSchema(schema) as Record<string, unknown>;
131	    const callStartedAt = Date.now();
132	    const ttl = pickAnthropicCacheTtl(plan.taskType, providerOptions);
133	
134	    // Force a single tool call. The tool's input_schema is the structured
135	    // output contract; Anthropic enforces it on the model.
136	    const TOOL_NAME = 'output_structured';
137	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
138	    const response = await this.client.messages.create({
139	      model: route.modelId,
140	      max_tokens: this.defaultMaxTokens,
141	      // Anthropic forbids temperature != 1 when thinking is enabled.
142	      temperature: thinking ? 1 : 0.1,
143	      system: this.buildSystem(plan, systemPrompt, providerOptions, ttl),
144	      messages: this.buildMessages(plan, userMessage, providerOptions, ttl),
145	      tools: [
146	        {
147	          name: TOOL_NAME,
148	          description:
149	            'Return the structured output. You MUST use this tool exactly once and never reply in plain text.',
150	          input_schema: jsonSchema as Anthropic.Tool.InputSchema,
151	        },
152	      ],
153	      tool_choice: { type: 'tool', name: TOOL_NAME },
154	      ...(thinking ? { thinking } : {}),
155	    });
156	    const latencyMs = Date.now() - callStartedAt;
157	    const toolUse = response.content.find((b) => b.type === 'tool_use');
158	    if (!toolUse || toolUse.type !== 'tool_use') {
159	      throw new Error(
160	        `AnthropicAdapter.generateObject: response contained no tool_use block. ` +
161	          `stop_reason=${response.stop_reason}`,
162	      );
163	    }
164	    const validated = tryZodParse<TOutput>(schema, toolUse.input);
165	    return {
166	      object: (validated ?? toolUse.input) as TOutput,
167	      usage: this.normalizeUsage(response, latencyMs),
168	      rawResponse: response,
169	    };
170	  }
171	
172	  /**
173	   * Submit a batch of requests to Anthropic's Message Batches API. Each
174	   * request reuses the same per-call shape as generateText / generateObject
175	   * but is bundled into a single `messages.batches.create` call. 50% off
176	   * sync pricing with a 24-hour SLA.
177	   *
178	   * When `jsonSchema` is provided, the batch is treated as generateObject:
179	   * each request gets a forced single tool call whose `input_schema` is the
180	   * structured-output contract (mirrors generateObject above).
181	   *
182	   * The batch ID alone is sufficient to retrieve results later, so
183	   * providerMetadata is an empty object (see types.ts SubmitBatchResult).
184	   */
185	  async submitBatch(args: SubmitBatchArgs): Promise<SubmitBatchResult> {
186	    const { route, requests, jsonSchema } = args;
187	    const thinking = thinkingParam(route.reasoningEffort, this.defaultMaxTokens);
188	    const TOOL_NAME = 'output_structured';
189	    const structuredTool = jsonSchema
190	      ? {
191	          name: TOOL_NAME,
192	          description:
193	            'Return the structured output. You MUST use this tool exactly once and never reply in plain text.',
194	          input_schema: jsonSchema as Anthropic.Tool.InputSchema,
195	        }
196	      : undefined;
197	
198	    const sdkRequests = requests.map((req) => {
199	      const { systemPrompt, userMessage } = flattenPlan(req.plan);
200	      const providerOptions = req.providerOptions;
201	      const params: MessageCreateParamsNonStreaming = {
202	        model: route.modelId,
203	        max_tokens: this.defaultMaxTokens,
204	        temperature: thinking
205	          ? 1
206	          : structuredTool
207	            ? 0.1
208	            : (typeof providerOptions?.temperature === 'number'
209	              ? providerOptions.temperature
210	              : undefined) as number | undefined,
211	        system: systemPrompt,
212	        messages: [{ role: 'user', content: userMessage }],
213	        ...(structuredTool
214	          ? {
215	              tools: [structuredTool],
216	              tool_choice: { type: 'tool', name: TOOL_NAME } as const,
217	            }
218	          : {}),
219	        ...(thinking ? { thinking } : {}),
220	      };
221	      return { custom_id: req.customId, params };
222	    });
223	
224	    const batch = await this.client.messages.batches.create({ requests: sdkRequests });
225	    return {
226	      providerBatchId: batch.id,
227	      providerMetadata: {},
228	    };
229	  }
230	
231	  /**
232	   * Poll status and, when terminal, stream the per-request results JSONL.
233	   * Each line carries the caller's `custom_id` so results map back to the
234	   * originating BatchRequest.
235	   *
236	   * Anthropic processing_status:
237	   *   in_progress | canceling → still running ('in_progress')
238	   *   ended                   → terminal; iterate results to build items
239	   *
240	   * Per-item `result.type`:
241	   *   succeeded → success; pull text or tool_use block
242	   *   errored   → failure with error.message
243	   *   canceled  → failure 'request canceled'
244	   *   expired   → failure 'request expired'
245	   */
246	  async retrieveBatch(args: RetrieveBatchArgs): Promise<RetrieveBatchResult> {
247	    const { providerBatchId } = args;
248	    const batch = await this.client.messages.batches.retrieve(providerBatchId);
249	    const counts = batch.request_counts;
250	    const requestCount =
251	      counts.processing + counts.succeeded + counts.errored + counts.canceled + counts.expired;
252	    const completedCount = counts.succeeded;
253	    const failedCount = counts.errored + counts.canceled + counts.expired;
254	
255	    if (batch.processing_status !== 'ended') {
256	      return {
257	        status: 'in_progress' as BatchStatus,
258	        requestCount,
259	        completedCount,
260	        failedCount,
261	      };
262	    }
263	
264	    const results: BatchResultItem[] = [];
265	    const stream = await this.client.messages.batches.results(providerBatchId);
266	    for await (const entry of stream as AsyncIterable<MessageBatchIndividualResponse>) {
267	      results.push(this.normalizeBatchResultItem(entry));
268	    }
269	
270	    return {
271	      status: 'completed',
272	      results,
273	      requestCount,
274	      completedCount,
275	      failedCount,
276	    };
277	  }
278	
279	  private normalizeBatchResultItem(entry: MessageBatchIndividualResponse): BatchResultItem {
280	    const customId = entry.custom_id;
281	    const result = entry.result;
282	    if (result.type === 'errored') {
283	      return {
284	        customId,
285	        success: false,
286	        error: result.error?.error?.message ?? 'errored',
287	      };
288	    }
289	    if (result.type === 'canceled') {
290	      return { customId, success: false, error: 'request canceled' };
291	    }
292	    if (result.type === 'expired') {
293	      return { customId, success: false, error: 'request expired' };
294	    }
295	    // succeeded
296	    const message = result.message;
297	    const usage = this.normalizeUsage(message, 0);
298	    const toolUse = message.content.find((b) => b.type === 'tool_use');
299	    if (toolUse && toolUse.type === 'tool_use') {
300	      return { customId, success: true, output: toolUse.input, usage };
301	    }
302	    return { customId, success: true, text: this.extractText(message), usage };
303	  }
304	
305	  /**
306	   * Build the system field. When caching is enabled and the system prompt is
307	   * non-empty, use the array-of-blocks form so we can attach
308	   * cache_control: { type: 'ephemeral' }. Otherwise pass the plain string.
309	   */
310	  private buildSystem(
311	    plan: GenerateTextArgs['plan'],
312	    systemPrompt: string,
313	    providerOptions?: Record<string, unknown>,
314	    ttl?: '5m' | '1h',
315	  ): string | Anthropic.TextBlockParam[] {
316	    if (!this.enableSystemPromptCache || systemPrompt.length === 0 || shouldDisableCache(providerOptions)) {
317	      return systemPrompt;
318	    }
319	    const minTokens = anthropicCacheMinTokens(plan.routeId);
320	    const stableTokens = estimatePlanStableTokens(plan);
321	    if (stableTokens < minTokens) return systemPrompt;
322	    return [
323	      {
324	        type: 'text',
325	        text: systemPrompt,
326	        cache_control: ttl ? { type: 'ephemeral', ttl } : { type: 'ephemeral' },
327	      },
328	    ];
329	  }
330	
331	  /**
332	   * Build the messages array. If the caller passed a multi-turn `messages`
333	   * override via providerOptions (chat route does this for R8 multi-turn),
334	   * pass it through; otherwise wrap the flattened user message in a single
335	   * user turn.
336	   */
337	  private buildMessages(
338	    plan: GenerateTextArgs['plan'],
339	    userMessage: string,
340	    providerOptions?: Record<string, unknown>,
341	    ttl?: '5m' | '1h',
342	  ): Anthropic.MessageParam[] {
343	    const override = providerOptions?.messages as
344	      | Array<{ role: string; content: unknown }>
345	      | undefined;
346	    if (Array.isArray(override) && override.length > 0) {
347	      const filtered = override
348	        .filter((m) => m.role === 'user' || m.role === 'assistant')
349	        .map((m) => ({
350	          role: m.role as 'user' | 'assistant',
351	          // Translate provider-neutral image parts → Anthropic base64 image block.
352	          content: toAnthropicImageContent(
353	            normalizeMessageContentArray(m.content),
354	          ) as unknown as Anthropic.MessageParam['content'],
355	        }));
356	      if (shouldDisableCache(providerOptions)) return filtered;
357	
358	      const hint = getCacheHints(providerOptions);
359	      const minTokens = anthropicCacheMinTokens(plan.routeId);
360	      const prefixText = filtered
361	        .slice(0, -1)
362	        .map((m) =>
363	          Array.isArray(m.content)
364	            ? m.content
365	                .map((part) => ('text' in part ? String(part.text ?? '') : ''))
366	                .join('\n')
367	            : '',
368	        )
369	        .join('\n');
370	      if (
371	        filtered.length > 1 &&
372	        (estimateText(prefixText) >= minTokens || hint?.preferExplicitCache)
373	      ) {
374	        const target = filtered[filtered.length - 2]!;
375	        target.content = markLastTextPartCacheable(
376	          target.content as unknown as Array<Record<string, unknown>>,
377	          ttl,
378	        ) as unknown as Anthropic.MessageParam['content'];
379	      }
380	      return filtered;
381	    }
382	    return [{ role: 'user', content: userMessage }];
383	  }
384	
385	  /** Extract concatenated text from response content blocks (ignores tool_use). */
386	  private extractText(response: Message): string {
387	    const parts: string[] = [];
388	    for (const block of response.content) {
389	      if (block.type === 'text') parts.push(block.text);
390	    }
391	    return parts.join('');
392	  }
393	
394	  /**
395	   * Normalize Anthropic usage into OracleUsage.
396	   *   - input_tokens                 -> inputTokens
397	   *   - output_tokens                -> outputTokens
398	   *   - cache_read_input_tokens      -> cachedInputTokens
399	   *   - cache_creation_input_tokens  -> cacheWriteTokens
400	   */
401	  private normalizeUsage(response: Message, latencyMs: number): OracleUsage {
402	    const u = response.usage;
403	    return {
404	      inputTokens: u.input_tokens,
405	      outputTokens: u.output_tokens,
406	      cachedInputTokens: u.cache_read_input_tokens ?? undefined,
407	      cacheWriteTokens: u.cache_creation_input_tokens ?? undefined,
408	      latencyMs,
409	      providerRequestId: response.id,
410	      rawUsageJson: u,
411	    };
412	  }
413	}
414	
415	function anthropicCacheMinTokens(routeId: string): number {
416	  return routeId.includes('haiku')
417	    ? ANTHROPIC_HAIKU_CACHE_MIN_TOKENS
418	    : ANTHROPIC_SONNET_CACHE_MIN_TOKENS;
419	}
420	
421	function estimateText(text: string): number {
422	  return Math.ceil(text.length / 4);
423	}
424	
425	/**
426	 * Build Anthropic's `thinking` request parameter from a unified effort enum.
427	 * Returns undefined when no thinking should be requested (off, undefined, or
428	 * when budget would exceed the model's max_tokens). The budget MUST be less
429	 * than max_tokens — Anthropic rejects the request otherwise.
430	 */
431	function thinkingParam(
432	  effort: ReasoningEffort | undefined,
433	  maxTokens: number,
434	): { type: 'enabled'; budget_tokens: number } | undefined {
435	  if (!effort || effort === 'off') return undefined;
436	  const targetBudget = effort === 'low' ? 2048 : effort === 'medium' ? 8192 : 24000;
437	  // Clamp so budget < max_tokens. Reserve at least 512 tokens for the answer.
438	  const budget = Math.max(1024, Math.min(targetBudget, maxTokens - 512));
439	  if (budget < 1024) return undefined;   // model can't fit even a low budget
440	  return { type: 'enabled', budget_tokens: budget };
441	}
