372	/**
373	 * OpenAI's strict JSON-schema mode rejects certain keywords that Zod's
374	 * converter emits but the OpenAPI subset doesn't support — most commonly
375	 * `$schema` and `default` on optional properties. `walk` strips those two
376	 * keys defensively so the schema validates server-side.
377	 */
378	function stripIncompatibleFields(
379	  schema: Record<string, unknown>,
380	): Record<string, unknown> {
381	  const cloned = JSON.parse(JSON.stringify(schema)) as Record<string, unknown>;
382	  walk(cloned);
383	  return cloned;
384	}
385	
386	/**
387	 * Translate unified ReasoningEffort to OpenAI's `reasoning_effort` enum.
388	 * Only meaningful for the o-series (o1/o3/o4) and GPT-5 reasoning models —
389	 * non-reasoning models silently accept and ignore the param.
390	 *
391	 * 'off' returns undefined so the caller can omit the param entirely.
392	 */
393	function openaiEffort(effort: ReasoningEffort | undefined): 'low' | 'medium' | 'high' | undefined {
394	  if (!effort || effort === 'off') return undefined;
395	  return effort; // 'low' | 'medium' | 'high' pass through unchanged
396	}
397	
398	function walk(node: unknown): void {
399	  if (node === null || typeof node !== 'object') return;
400	  if (Array.isArray(node)) {
401	    for (const item of node) walk(item);
402	    return;
403	  }
404	  const obj = node as Record<string, unknown>;
405	  delete obj.$schema;
406	  delete obj.default;
407	  for (const value of Object.values(obj)) walk(value);
408	}
409	
410	/**
411	 * Map OpenAI's batch.status enum onto our provider-agnostic BatchStatus.
412	 *
413	 *   validating | in_progress | finalizing → 'in_progress'
414	 *   completed                              → 'completed'
415	 *   failed                                 → 'failed'
416	 *   expired                                → 'expired'
417	 *   cancelling | cancelled                 → 'canceled'
418	 */
419	function mapOpenAIBatchStatus(s: string): BatchStatus {
420	  switch (s) {
421	    case 'completed': return 'completed';
422	    case 'failed': return 'failed';
423	    case 'expired': return 'expired';
424	    case 'cancelling':
425	    case 'cancelled':
426	      return 'canceled';
427	    case 'validating':
428	    case 'in_progress':
429	    case 'finalizing':
430	      return 'in_progress';
431	    default:
432	      // Unknown → treat as still-running so the drain task polls again
433	      return 'in_progress';
434	  }
435	}
