33	export class GoogleGeminiAdapter implements OracleProviderAdapter {
34	  readonly provider = 'google' as const;
35	  private readonly client: GoogleGenAI | null;
36	  private readonly serviceAccountJson: string | null;
37	
38	  constructor(opts: GoogleGeminiAdapterOptions = {}) {
39	    const apiKey = opts.apiKey ?? process.env.GEMINI_API_KEY ?? process.env.GOOGLE_API_KEY;
40	    this.serviceAccountJson = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON ?? null;
41	    if (!apiKey && !this.serviceAccountJson) {
