88	
89	  async generateObject<TSchema, TOutput>(
90	    args: GenerateObjectArgs<TSchema>,
91	  ): Promise<OracleObjectResult<TOutput>> {
92	    const { plan, route, schema, providerOptions } = args;
93	    const { systemPrompt, userMessage } = flattenPlan(plan);
94	    const callStartedAt = Date.now();
95	
96	    const contents: Content[] = [{ role: 'user', parts: [{ text: userMessage }] }];
97	    const jsonSchema = zodToJsonSchema(schema);
98	    const commonConfig = {
99	      temperature: 0.1,
100	      ...geminiThinkingConfig(route.reasoningEffort),
101	    };
102	    const sdkConfig = {
103	      ...commonConfig,
104	      responseMimeType: 'application/json',
105	      responseJsonSchema: jsonSchema as unknown,
106	    };
107	    const restConfig = {
108	      ...commonConfig,
109	      responseMimeType: 'application/json',
110	      responseSchema: toGeminiRestSchema(jsonSchema),
111	    };
112	    const response = this.client
113	      ? await this.client.models.generateContent({
114	          model: route.modelId,
115	          contents,
116	          config: sdkConfig,
117	        })
118	      : await this.generateContentWithOAuth({
119	          modelId: route.modelId,
120	          contents,
121	          systemPrompt,
122	          generationConfig: restConfig,
123	        });
