125	    const text = extractTextFromGeminiResponse(response);
126	    const parsed = parseJsonOrRaw(text);
127	    const validated = tryZodParse<TOutput>(schema, parsed);
128	
129	    return {
130	      object: (validated ?? parsed) as TOutput,
131	      usage: normalizeGeminiUsage(response, Date.now() - callStartedAt),
132	      rawResponse: response,
133	    };
