135	
136	  private async generateContentWithOAuth(input: {
137	    modelId: string;
138	    contents: Content[];
139	    systemPrompt: string;
140	    generationConfig: Record<string, unknown>;
141	  }): Promise<GenerateContentResponse> {
142	    if (!this.serviceAccountJson) {
143	      throw new Error('GoogleGeminiAdapter: service account JSON missing for OAuth request.');
144	    }
145	    const token = await getGenerativeLanguageAccessToken(this.serviceAccountJson);
146	    const res = await fetch(
147	      `https://generativelanguage.googleapis.com/v1beta/models/${input.modelId}:generateContent`,
148	      {
149	        method: 'POST',
150	        headers: {
151	          Authorization: `Bearer ${token}`,
152	          'Content-Type': 'application/json',
153	          Accept: 'application/json',
154	        },
155	        body: JSON.stringify({
156	          contents: input.contents,
157	          systemInstruction: input.systemPrompt
158	            ? { parts: [{ text: input.systemPrompt }] }
159	            : undefined,
160	          generationConfig: stripUndefined(input.generationConfig),
161	        }),
162	        signal: AbortSignal.timeout(60_000),
163	      },
164	    );
165	    if (!res.ok) {
166	      throw new Error(`Gemini API generateContent failed: ${res.status} ${await res.text()}`);
167	    }
168	    return (await res.json()) as GenerateContentResponse;
169	  }
170	}
171	
172	function buildContents(
173	  userMessage: string,
174	  providerOptions?: Record<string, unknown>,
175	): Content[] {
176	  const messages = providerOptions?.messages as
177	    | Array<{ role: 'user' | 'assistant' | 'system'; content: unknown }>
178	    | undefined;
179	  if (Array.isArray(messages) && messages.length > 0) {
180	    return messages
181	      .filter((m) => m.role !== 'system')
182	      .map((m) => ({
183	        role: m.role === 'assistant' ? 'model' : 'user',
184	        parts: toGeminiParts(m.content),
185	      }));
186	  }
187	  return [{ role: 'user', parts: [{ text: userMessage }] }];
188	}
189	
190	function toGeminiParts(content: unknown): Part[] {
191	  if (typeof content === 'string') return [{ text: content }];
192	  if (!Array.isArray(content)) return [{ text: String(content ?? '') }];
193	  const parts: Part[] = [];
194	  for (const raw of content) {
195	    if (raw && typeof raw === 'object') {
196	      const part = raw as Record<string, unknown>;
197	      if (
198	        part.type === 'image' &&
199	        typeof part.data === 'string' &&
200	        typeof part.mimeType === 'string'
201	      ) {
202	        parts.push({ inlineData: { mimeType: part.mimeType, data: part.data } });
203	        continue;
204	      }
205	      if ((part.type === 'text' || part.type === undefined) && typeof part.text === 'string') {
206	        parts.push({ text: part.text });
207	        continue;
208	      }
209	    }
210	    parts.push({ text: String(raw) });
211	  }
212	  return parts;
213	}
214	
215	function geminiThinkingConfig(effort: ReasoningEffort | undefined):
216	  | { thinkingConfig: { thinkingLevel: ThinkingLevel } }
217	  | Record<string, never> {
218	  if (!effort) return {};
219	  const thinkingLevel =
220	    effort === 'off' ? ThinkingLevel.MINIMAL
221	      : effort === 'low' ? ThinkingLevel.LOW
222	      : effort === 'medium' ? ThinkingLevel.MEDIUM
223	      : ThinkingLevel.HIGH;
224	  return { thinkingConfig: { thinkingLevel } };
225	}
226	
227	function normalizeGeminiUsage(
228	  response: GenerateContentResponse,
229	  latencyMs: number,
230	): OracleUsage {
231	  const u = response.usageMetadata ?? {};
232	  return {
233	    inputTokens: u.promptTokenCount,
234	    outputTokens: u.candidatesTokenCount,
235	    cachedInputTokens: u.cachedContentTokenCount,
236	    reasoningTokens: u.thoughtsTokenCount,
237	    latencyMs,
238	    providerRequestId: response.responseId,
239	    rawUsageJson: u,
240	  };
241	}
242	
243	function extractTextFromGeminiResponse(response: GenerateContentResponse): string {
244	  if (typeof response.text === 'string') return response.text;
245	  const candidateText = response.candidates
246	    ?.flatMap((candidate) => candidate.content?.parts ?? [])
247	    .map((part) => ('text' in part && typeof part.text === 'string' ? part.text : ''))
248	    .join('');
249	  return candidateText ?? '';
250	}
251	
252	async function getGenerativeLanguageAccessToken(saJson: string): Promise<string> {
253	  const sa = parseServiceAccountJson(saJson);
254	  const now = Math.floor(Date.now() / 1000);
255	
256	  const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
257	  const payload = Buffer.from(
258	    JSON.stringify({
259	      iss: sa.client_email,
260	      scope: 'https://www.googleapis.com/auth/generative-language',
261	      aud: 'https://oauth2.googleapis.com/token',
262	      iat: now,
263	      exp: now + 3600,
264	    }),
265	  ).toString('base64url');
266	
267	  const signer = createSign('SHA256');
268	  signer.update(`${header}.${payload}`);
269	  const sig = signer.sign({ key: sa.private_key, format: 'pem' }, 'base64url');
270	  const jwt = `${header}.${payload}.${sig}`;
271	
272	  const res = await fetch('https://oauth2.googleapis.com/token', {
273	    method: 'POST',
274	    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
275	    body: new URLSearchParams({
276	      grant_type: 'urn:ietf:params:oauth:grant-type:jwt-bearer',
277	      assertion: jwt,
278	    }),
279	    signal: AbortSignal.timeout(10_000),
280	  });
281	  if (!res.ok) {
282	    throw new Error(`Google token exchange failed: ${res.status} ${await res.text()}`);
283	  }
284	  const data = (await res.json()) as { access_token: string };
285	  return data.access_token;
286	}
287	
288	function parseServiceAccountJson(saJson: string): { client_email: string; private_key: string } {
289	  try {
290	    return JSON.parse(saJson) as { client_email: string; private_key: string };
291	  } catch {
292	    // Vercel env pulls can materialize the PEM as literal newlines inside the
293	    // JSON string. Normalize just that field, then parse normally.
294	    const normalized = saJson.replace(
295	      /"private_key"\s*:\s*"([\s\S]*?)"/,
296	      (_match, key: string) => `"private_key":"${key.replace(/\r?\n/g, '\\n')}"`,
297	    );
298	    return JSON.parse(normalized) as { client_email: string; private_key: string };
299	  }
300	}
301	
302	function stripUndefined<T extends Record<string, unknown>>(obj: T): Record<string, unknown> {
303	  return Object.fromEntries(Object.entries(obj).filter(([, value]) => value !== undefined));
304	}
305	
306	function toGeminiRestSchema(schema: unknown): unknown {
307	  if (Array.isArray(schema)) return schema.map(toGeminiRestSchema);
308	  if (!schema || typeof schema !== 'object') return schema;
309	
310	  const output: Record<string, unknown> = {};
311	  for (const [key, value] of Object.entries(schema)) {
312	    if (key === '$schema' || key === 'additionalProperties') continue;
313	    output[key] = toGeminiRestSchema(value);
314	  }
315	  return output;
316	}
