205	        // responseJsonSchema accepts standard JSON Schema as of @google/genai 2.6.
206	        responseJsonSchema: jsonSchema as unknown,
207	        ...(explicitCache?.cacheName ? { cachedContent: explicitCache.cacheName } : {}),
208	        ...vertexThinkingConfig(route.reasoningEffort),
209	      },
210	    });
211	    const latencyMs = Date.now() - callStartedAt;
212	    await this.recordSuccessfulExplicitCacheReuse(explicitCache);
213	    const text = response.text ?? '';
214	    const parsed = parseJsonOrRaw(text);
215	    // Best-effort runtime validation if a Zod schema was supplied — gives the
216	    // caller a typed error rather than silently passing through malformed output.
217	    const validated = tryZodParse<TOutput>(schema, parsed);
218	    return {
219	      object: (validated ?? parsed) as TOutput,
220	      usage: this.normalizeUsage(response, latencyMs),
221	      rawResponse: response,
222	    };
223	  }
224	
225	  /**
226	   * Translate `providerOptions.messages` (a multi-turn array shaped for the
227	   * Vercel AI SDK / OpenAI chat format) into Vertex's `contents` shape, or
228	   * fall back to a single user turn when no override is present.
229	   */
230	  private buildContents(
231	    userMessage: string,
232	    providerOptions?: Record<string, unknown>,
233	  ): Content[] {
234	    const messages = providerOptions?.messages as
235	      | Array<{ role: 'user' | 'assistant' | 'system'; content: unknown }>
236	      | undefined;
237	    if (Array.isArray(messages) && messages.length > 0) {
238	      // Vertex uses 'model' instead of 'assistant'; system goes in
239	      // systemInstruction not contents. Content may be a plain string or a
240	      // multimodal part array (text + inline images) — see toVertexParts.
241	      return messages
242	        .filter((m) => m.role !== 'system')
243	        .map((m) => ({
244	          role: m.role === 'assistant' ? 'model' : 'user',
245	          parts: toVertexParts(m.content),
246	        }));
247	    }
248	    return [{ role: 'user', parts: [{ text: userMessage }] }];
249	  }
250	
251	  private async prepareExplicitCacheForText(
252	    plan: OraclePromptPlan,
253	    modelId: string,
254	    systemPrompt: string,
255	    contents: Content[],
256	    providerOptions?: Record<string, unknown>,
257	  ): Promise<{
258	    cacheName?: string;
259	    omitSystemInstruction: boolean;
260	      contentsForRequest: Content[];
261	      requestUserMessage?: string;
262	      lifecycleHandle?: CacheLifecycleHandle;
263	  } | null> {
264	    const hints = getCacheHints(providerOptions);
265	    const fileCache = await this.prepareExplicitFileCache(plan, modelId, systemPrompt, providerOptions);
266	    if (fileCache) {
267	      // The cached prefix already carries systemInstruction + the file artifact.
268	      // For multi-turn chat (interview route), send the FULL conversation as the
269	      // live contents on top of the cache so history is preserved. Only collapse
270	      // to the single dynamicInput turn when there is no conversation — e.g. a
271	      // single-shot text call whose document corpus is the whole input.
272	      const liveContents =
273	        contents.length > 0
274	          ? contents
275	          : [{ role: 'user' as const, parts: [{ text: fileCache.dynamicInput }] }];
276	      return {
277	        cacheName: fileCache.name,
278	        omitSystemInstruction: true,
279	        contentsForRequest: liveContents,
280	        requestUserMessage: fileCache.dynamicInput,
281	        lifecycleHandle: fileCache.lifecycleHandle,
282	      };
283	    }
284	    const prefixContents = contents.slice(0, -1);
285	    const latestTurn = contents[contents.length - 1];
286	    const prefixText = prefixContents
287	      .flatMap((content) => content.parts ?? [])
288	      .map((part) => String(part.text ?? ''))
289	      .join('\n');
290	    const stableTokens = estimatePlanStableTokens(plan);
291	    const prefixTokens = estimateTextTokens(prefixText);
292	    const shouldCreate =
293	      hints?.preferExplicitCache === true ||
294	      prefixTokens >= 2048 ||
295	      stableTokens >= 2048;
296	    if (!shouldCreate || !latestTurn) return null;
297	
298	    const cachePayload = prefixContents.length > 0
299	      ? { contents: prefixContents, includesSystemInstruction: !!systemPrompt }
300	      : { contents: [], includesSystemInstruction: !!systemPrompt };

1	/**
2	 * DeepSeekAdapter — direct DeepSeek API integration via the official `openai`
3	 * SDK pointed at api.deepseek.com.
4	 *
5	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
6	 * - Calls DeepSeek's REST API directly using the OpenAI-compatible surface.
7	 * - NO Vercel AI SDK and NO OpenRouter in this path.
8	 * - Authenticates via `DEEPSEEK_API_KEY` env var.
9	 *
10	 * Caching strategy (automatic prefix caching):
11	 * - DeepSeek auto-caches prompts on stable prefixes — no client action required.
12	 * - Cache hits surface in `usage.prompt_cache_hit_tokens` and misses in
13	 *   `usage.prompt_cache_miss_tokens` (DeepSeek-specific fields, NOT the OpenAI
14	 *   `prompt_tokens_details.cached_tokens` shape).
15	 *
16	 * Structured output:
17	 * - DeepSeek supports OpenAI-compatible `response_format: { type: 'json_object' }`
18	 *   for free-form JSON. Strict JSON-schema mode is NOT supported as of writing,
19	 *   so generateObject falls back to json_object + Zod validation.
20	 *
21	 * Reasoning models:
22	 * - `deepseek-reasoner` returns the chain-of-thought in `message.reasoning_content`
23	 *   (separate from `message.content`). We surface reasoning_content tokens in
24	 *   OracleUsage.reasoningTokens when present.
25	 */
26	
27	import OpenAI from 'openai';
28	import type { ChatCompletion, ChatCompletionMessageParam } from 'openai/resources/chat/completions';
29	import type {
30	  OracleObjectResult,
31	  OracleTextResult,
32	  OracleUsage,
33	} from '../client/types';
34	import type {
35	  GenerateObjectArgs,
36	  GenerateTextArgs,
37	  OracleProviderAdapter,
38	} from './types';
39	import { normalizeMessageContentArray, toOpenAIImageContent } from './cache-utils';
40	import { flattenPlan, parseJsonOrRaw, tryZodParse } from './vertex-gemini-adapter';
41	
42	const DEEPSEEK_BASE_URL = 'https://api.deepseek.com';
43	
44	export interface DeepSeekAdapterOptions {
45	  /** API key. Defaults to env DEEPSEEK_API_KEY. */
46	  apiKey?: string;
47	  /** Override base URL (e.g. for proxy or China-region endpoint). */
48	  baseURL?: string;
49	}
50	
51	/** DeepSeek's usage object extends OpenAI's with cache hit/miss fields. */
52	interface DeepSeekUsageRaw {
53	  prompt_tokens?: number;
54	  completion_tokens?: number;
55	  prompt_cache_hit_tokens?: number;
56	  prompt_cache_miss_tokens?: number;
57	  completion_tokens_details?: { reasoning_tokens?: number };
58	  total_tokens?: number;
59	}
60	
61	export class DeepSeekAdapter implements OracleProviderAdapter {
62	  readonly provider = 'deepseek' as const;
63	  private readonly client: OpenAI;
64	
65	  constructor(opts: DeepSeekAdapterOptions = {}) {
66	    const apiKey = opts.apiKey ?? process.env.DEEPSEEK_API_KEY;
67	    if (!apiKey) {
68	      throw new Error(
69	        'DeepSeekAdapter: DEEPSEEK_API_KEY is not set. ' +
70	          'Set it in .env.local or pass {apiKey} explicitly.',
71	      );
72	    }
73	    this.client = new OpenAI({
74	      apiKey,
75	      baseURL: opts.baseURL ?? DEEPSEEK_BASE_URL,
76	    });
77	  }
78	
79	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
80	    const { plan, route, providerOptions } = args;
81	    const { systemPrompt, userMessage } = flattenPlan(plan);
82	    const messages = this.buildMessages(systemPrompt, userMessage, providerOptions);
83	    // DeepSeek-reasoner does reasoning internally with no client-side budget
84	    // control. Log when an effort was requested so observability can surface
85	    // it; the value is otherwise ignored at the API layer.
86	    if (route.reasoningEffort && route.reasoningEffort !== 'off') {
87	      // eslint-disable-next-line no-console
88	      console.info(
89	        `[DeepSeekAdapter] reasoningEffort=${route.reasoningEffort} requested for ${route.modelId} — model controls reasoning internally; param ignored.`,
90	      );
91	    }
92	    const callStartedAt = Date.now();
93	    const completion = await this.client.chat.completions.create({
94	      model: route.modelId,
95	      messages,
96	      temperature:
97	        typeof providerOptions?.temperature === 'number'
98	          ? providerOptions.temperature
99	          : undefined,
100	      ...(typeof providerOptions?.maxOutputTokens === 'number'
101	        ? { max_tokens: providerOptions.maxOutputTokens }
102	        : {}),
103	    });
104	    const latencyMs = Date.now() - callStartedAt;
105	    const choice = completion.choices[0];
106	    return {
107	      text: choice?.message?.content ?? '',
108	      usage: this.normalizeUsage(completion, latencyMs),
109	      rawResponse: completion,
110	    };
111	  }
112	
113	  async generateObject<TSchema, TOutput>(
114	    args: GenerateObjectArgs<TSchema>,
115	  ): Promise<OracleObjectResult<TOutput>> {
116	    const { plan, route, schema, providerOptions } = args;
117	    const { systemPrompt, userMessage } = flattenPlan(plan);
118	    // DeepSeek supports json_object (free-form JSON), not strict json_schema.
119	    // We embed schema guidance in the system prompt and validate with Zod after.
120	    const callStartedAt = Date.now();
121	    const completion = await this.client.chat.completions.create({
122	      model: route.modelId,
123	      messages: this.buildMessages(systemPrompt, userMessage, providerOptions),
124	      temperature:
125	        typeof providerOptions?.temperature === 'number'
126	          ? providerOptions.temperature
127	          : 0.1,
128	      response_format: { type: 'json_object' },
129	    });
130	    const latencyMs = Date.now() - callStartedAt;
131	    const choice = completion.choices[0];
132	    const raw = choice?.message?.content;
133	    if (!raw) {
134	      throw new Error(
135	        `DeepSeekAdapter.generateObject: empty response. finish_reason=${choice?.finish_reason}`,
136	      );
137	    }
138	    const parsed = parseJsonOrRaw(raw);
139	    const validated = tryZodParse<TOutput>(schema, parsed);
140	    return {
141	      object: (validated ?? parsed) as TOutput,
142	      usage: this.normalizeUsage(completion, latencyMs),
143	      rawResponse: completion,
144	    };
145	  }
146	
147	  private buildMessages(
148	    systemPrompt: string,
149	    userMessage: string,
150	    providerOptions?: Record<string, unknown>,
151	  ): ChatCompletionMessageParam[] {
152	    const override = providerOptions?.messages as
153	      | Array<{ role: string; content: unknown }>
154	      | undefined;
155	    if (Array.isArray(override) && override.length > 0) {
156	      const normalized = override.map((m) => ({
157	        role: m.role,
158	        content: toOpenAIImageContent(
159	          Array.isArray(m.content) ? normalizeMessageContentArray(m.content) : m.content,
160	        ),
161	      })) as unknown as ChatCompletionMessageParam[];
162	      if (systemPrompt && !normalized.some((m) => m.role === 'system')) {
163	        return [{ role: 'system', content: systemPrompt }, ...normalized];
164	      }
165	      return normalized;
166	    }
167	    const msgs: ChatCompletionMessageParam[] = [];
168	    if (systemPrompt) msgs.push({ role: 'system', content: systemPrompt });
169	    msgs.push({ role: 'user', content: userMessage });
170	    return msgs;
171	  }
172	
173	  /**
174	   * Normalize DeepSeek usage. Cache hits live in `prompt_cache_hit_tokens`
175	   * (NOT the OpenAI prompt_tokens_details shape). The OpenAI SDK exposes
176	   * the raw object on `usage` — we cast through unknown to read DeepSeek's
177	   * extra fields.
178	   */
179	  private normalizeUsage(
180	    completion: ChatCompletion,
181	    latencyMs: number,
182	  ): OracleUsage {
183	    const u = completion.usage as unknown as DeepSeekUsageRaw | undefined;
184	    return {
185	      inputTokens: u?.prompt_tokens,
186	      outputTokens: u?.completion_tokens,
187	      cachedInputTokens: u?.prompt_cache_hit_tokens,
188	      reasoningTokens: u?.completion_tokens_details?.reasoning_tokens,
189	      latencyMs,
190	      providerRequestId: completion.id,
191	      rawUsageJson: u,
192	    };
193	  }
194	}
