1	/**
2	 * QwenAdapter — direct Alibaba Qwen integration via Alibaba DashScope's
3	 * OpenAI-compatible endpoint.
4	 *
5	 * Architecture (DECISIONS.md D6, docs/oracle/02 §"Shared architecture"):
6	 * - Calls DashScope's OpenAI-compatible REST API using the official `openai` SDK.
7	 * - NO Vercel AI SDK and NO OpenRouter in this path.
8	 * - Authenticates via `DASHSCOPE_API_KEY` env var.
9	 *
10	 * Caching strategy:
11	 * - DashScope's OpenAI-compatible Chat Completions endpoint supports explicit
12	 *   prompt caching via per-content-block `cache_control` markers.
13	 * - This adapter marks the reusable prefix explicitly:
14	 *   - for multi-turn chat, the prefix ends at the penultimate message so the
15	 *     latest user turn stays dynamic
16	 *   - for one-shot calls, the stable system prompt is marked cacheable
17	 * - For text calls, the adapter can switch to the Responses API session-cache
18	 *   path when the caller supplies a stable `sessionCacheKey`. The chat route
19	 *   persists `previous_response_id` in Postgres so the cache survives across
20	 *   requests and processes.
21	 *
22	 * Structured output:
23	 * - Qwen supports OpenAI-compatible `response_format: { type: 'json_object' }`.
24	 *   Strict json_schema mode is not universally supported, so generateObject
25	 *   falls back to json_object + Zod validation (same pattern as DeepSeek).
26	 *
27	 * Reasoning models:
28	 * - QwQ / Qwen-3 thinking models stream reasoning tokens but don't yet expose
29	 *   a separate reasoning_content field on the OpenAI-compat endpoint. We
30	 *   capture only standard input/output tokens.
31	 */
32	
33	import OpenAI from 'openai';
34	import type { ChatCompletion, ChatCompletionMessageParam } from 'openai/resources/chat/completions';
35	import type {
36	  EasyInputMessage,
37	  Response as OpenAIResponse,
38	  ResponseUsage,
39	} from 'openai/resources/responses/responses';
40	import type {
41	  OracleObjectResult,
42	  OracleTextResult,
43	  OracleUsage,
44	} from '../client/types';
45	import type { ReasoningEffort } from '../routes';
46	import type {
47	  GenerateObjectArgs,
48	  GenerateTextArgs,
49	  OracleProviderAdapter,
50	} from './types';
51	import {
52	  getCacheHints,
53	  markLastTextPartCacheable,
54	  normalizeMessageContentArray,
55	  pickAnthropicCacheTtl,
56	  pickOpenAICacheRetention,
57	  shouldDisableCache,
58	  toOpenAIImageContent,
59	} from './cache-utils';
60	import { flattenPlan, parseJsonOrRaw, tryZodParse } from './vertex-gemini-adapter';
61	
62	const DASHSCOPE_BASE_URL = 'https://dashscope-us.aliyuncs.com/compatible-mode/v1';
63	
64	export interface QwenAdapterOptions {
65	  /** API key. Defaults to env DASHSCOPE_API_KEY. */
66	  apiKey?: string;
67	  /** Override base URL — e.g. swap to the China-region endpoint
68	   *  `https://dashscope.aliyuncs.com/compatible-mode/v1`. */
69	  baseURL?: string;
70	}
71	
72	interface QwenUsageRaw {
73	  prompt_tokens?: number;
74	  completion_tokens?: number;
75	  // DashScope reports cache READS in prompt_tokens_details.cached_tokens.
76	  // It does NOT report cache-creation/write tokens, so there is no
77	  // cacheWriteTokens-equivalent field to read here.
78	  prompt_tokens_details?: {
79	    cached_tokens?: number;
80	  };
81	}
82	
83	export class QwenAdapter implements OracleProviderAdapter {
84	  readonly provider = 'qwen' as const;
85	  private readonly client: OpenAI;
86	
87	  constructor(opts: QwenAdapterOptions = {}) {
88	    const apiKey = opts.apiKey ?? process.env.DASHSCOPE_API_KEY;
89	    if (!apiKey) {
90	      throw new Error(
91	        'QwenAdapter: DASHSCOPE_API_KEY is not set. ' +
92	          'Set it in .env.local or pass {apiKey} explicitly.',
93	      );
94	    }
95	    this.client = new OpenAI({
96	      apiKey,
97	      // Region-configurable: some models (e.g. qwen3-vl-*) are only served on the
98	      // intl endpoint. Override with DASHSCOPE_BASE_URL (e.g.
99	      // https://dashscope-intl.aliyuncs.com/compatible-mode/v1).
100	      baseURL: opts.baseURL ?? process.env.DASHSCOPE_BASE_URL ?? DASHSCOPE_BASE_URL,
101	    });
102	  }
103	
104	  async generateText(args: GenerateTextArgs): Promise<OracleTextResult> {
105	    const { plan, route, providerOptions } = args;
106	    const { systemPrompt, userMessage } = flattenPlan(plan);
107	    const hints = getCacheHints(providerOptions);
108	    if (hints?.sessionCacheKey || hints?.previousResponseId) {
109	      return this.generateTextViaResponsesApi(
110	        plan.taskType,
111	        route,
112	        systemPrompt,
113	        userMessage,
114	        providerOptions,
115	      );
116	    }
117	    const messages = this.buildMessages(plan.taskType, systemPrompt, userMessage, providerOptions);
118	    const callStartedAt = Date.now();
119	    const completion = await this.client.chat.completions.create({
120	      model: route.modelId,
121	      messages,
122	      temperature:
123	        typeof providerOptions?.temperature === 'number'
124	          ? providerOptions.temperature
125	          : undefined,
126	      // Output-token budget (vision transcription of dense diagrams + the
127	      // thinking trace need a high cap or DashScope truncates mid-reasoning).
128	      ...(typeof providerOptions?.maxOutputTokens === 'number'
129	        ? { max_tokens: providerOptions.maxOutputTokens }
130	        : {}),
131	      // For qwen-vl, DashScope downscales images to a default pixel budget,
132	      // which makes a dense diagram's small text unreadable (the model then
133	      // confabulates). `vl_high_resolution_images: true` keeps full resolution.
134	      ...(providerOptions?.highResolutionVision === true
135	        ? { vl_high_resolution_images: true }
136	        : {}),
137	      // Qwen-specific reasoning controls pass through via `extra_body`.
138	      // DashScope's OpenAI-compat layer forwards unknown root-level params.
139	      ...qwenThinkingExtras(route.reasoningEffort),
140	    });
141	    const latencyMs = Date.now() - callStartedAt;
142	    const choice = completion.choices[0];
143	    return {
144	      text: choice?.message?.content ?? '',
145	      usage: this.normalizeUsage(completion, latencyMs),
146	      rawResponse: completion,
147	    };
148	  }
149	
150	  private async generateTextViaResponsesApi(
151	    taskType: GenerateTextArgs['plan']['taskType'],
152	    route: GenerateTextArgs['route'],
153	    systemPrompt: string,
154	    userMessage: string,
155	    providerOptions?: Record<string, unknown>,
156	  ): Promise<OracleTextResult> {
157	    const hints = getCacheHints(providerOptions);
158	    const callStartedAt = Date.now();
159	    const response = await this.client.responses.create(
160	      {
161	        model: route.modelId,
162	        instructions: systemPrompt || undefined,
163	        input: this.buildResponseInput(userMessage, providerOptions),
164	        temperature:
165	          typeof providerOptions?.temperature === 'number'
166	            ? providerOptions.temperature
167	            : undefined,
168	        prompt_cache_key: hints?.sessionCacheKey,
169	        previous_response_id: hints?.previousResponseId,
170	        prompt_cache_retention: pickOpenAICacheRetention(taskType, providerOptions),
171	        ...qwenThinkingExtras(route.reasoningEffort),
172	      },
173	      {
174	        headers: {
175	          'x-dashscope-session-cache': 'enable',
176	        },
177	      },
178	    );
179	    const latencyMs = Date.now() - callStartedAt;
180	    return {
181	      text: response.output_text ?? '',
182	      usage: this.normalizeResponseUsage(response, latencyMs),
183	      rawResponse: response,
184	    };
185	  }
186	
187	  async generateObject<TSchema, TOutput>(
188	    args: GenerateObjectArgs<TSchema>,
189	  ): Promise<OracleObjectResult<TOutput>> {
190	    const { plan, route, schema, providerOptions } = args;
191	    const { systemPrompt, userMessage } = flattenPlan(plan);
192	    const callStartedAt = Date.now();
193	    const completion = await this.client.chat.completions.create({
194	      model: route.modelId,
195	      messages: this.buildMessages(plan.taskType, systemPrompt, userMessage, providerOptions),
196	      temperature: 0.1,
197	      response_format: { type: 'json_object' },
198	      ...qwenThinkingExtras(route.reasoningEffort),
199	    });
200	    const latencyMs = Date.now() - callStartedAt;
201	    const choice = completion.choices[0];
202	    const raw = choice?.message?.content;
203	    if (!raw) {
204	      throw new Error(
205	        `QwenAdapter.generateObject: empty response. finish_reason=${choice?.finish_reason}`,
206	      );
207	    }
208	    const parsed = parseJsonOrRaw(raw);
209	    const validated = tryZodParse<TOutput>(schema, parsed);
210	    return {
211	      object: (validated ?? parsed) as TOutput,
212	      usage: this.normalizeUsage(completion, latencyMs),
213	      rawResponse: completion,
214	    };
215	  }
216	
217	  private buildMessages(
218	    taskType: GenerateTextArgs['plan']['taskType'],
219	    systemPrompt: string,
220	    userMessage: string,
221	    providerOptions?: Record<string, unknown>,
222	  ): ChatCompletionMessageParam[] {
223	    const override = providerOptions?.messages as
224	      | Array<{ role: string; content: unknown }>
225	      | undefined;
226	    if (Array.isArray(override) && override.length > 0) {
227	      const normalized = override.map((m) => ({
228	        role: m.role,
229	        // Translate provider-neutral image parts → OpenAI `image_url` at dispatch,
230	        // so a fallback into this adapter still sends a readable image.
231	        content: toOpenAIImageContent(m.content),
232	      })) as unknown as ChatCompletionMessageParam[];
233	      if (systemPrompt && !normalized.some((m) => m.role === 'system')) {
234	        normalized.unshift({ role: 'system', content: systemPrompt });
235	      }
236	      return this.applyExplicitCacheMarkers(taskType, normalized, providerOptions);
237	    }
238	    const msgs: ChatCompletionMessageParam[] = [];
239	    if (systemPrompt) msgs.push({ role: 'system', content: systemPrompt });
240	    msgs.push({ role: 'user', content: userMessage });
241	    return this.applyExplicitCacheMarkers(taskType, msgs, providerOptions);
242	  }
243	
244	  private normalizeUsage(
245	    completion: ChatCompletion,
246	    latencyMs: number,
247	  ): OracleUsage {
248	    const u = completion.usage as QwenUsageRaw | undefined;
249	    // DashScope does not report cache-creation (write) tokens — only reads via
250	    // prompt_tokens_details.cached_tokens — so cacheWriteTokens is omitted.
251	    return {
252	      inputTokens: u?.prompt_tokens,
253	      outputTokens: u?.completion_tokens,
254	      cachedInputTokens: u?.prompt_tokens_details?.cached_tokens,
255	      latencyMs,
256	      providerRequestId: completion.id,
257	      rawUsageJson: u,
258	    };
259	  }
260	
261	  private normalizeResponseUsage(
262	    response: OpenAIResponse,
263	    latencyMs: number,
264	  ): OracleUsage {
265	    const u = response.usage as ResponseUsage | undefined;
266	    return {
267	      inputTokens: u?.input_tokens,
268	      outputTokens: u?.output_tokens,
269	      cachedInputTokens: u?.input_tokens_details?.cached_tokens,
270	      reasoningTokens: u?.output_tokens_details?.reasoning_tokens,
271	      latencyMs,
272	      providerRequestId: response.id,
273	      rawUsageJson: u,
274	    };
275	  }
276	
277	  private applyExplicitCacheMarkers(
278	    taskType: GenerateTextArgs['plan']['taskType'],
279	    messages: ChatCompletionMessageParam[],
280	    providerOptions?: Record<string, unknown>,
281	  ): ChatCompletionMessageParam[] {
282	    if (shouldDisableCache(providerOptions)) return messages;
283	    const ttl = pickAnthropicCacheTtl(taskType, providerOptions);
284	    const next = messages.map((message) => ({ ...message }));
285	
286	    if (next.length > 1) {
287	      const target = next[next.length - 2] as ChatCompletionMessageParam & { content?: unknown };
288	      target.content = markLastTextPartCacheable(
289	        normalizeMessageContentArray(target.content),
290	        ttl,
291	      ) as unknown as ChatCompletionMessageParam['content'];
292	      return next;
293	    }
294	
295	    const system = next.find((message) => message.role === 'system') as
296	      | (ChatCompletionMessageParam & { content?: unknown })
297	      | undefined;
298	    if (system) {
299	      system.content = markLastTextPartCacheable(
300	        normalizeMessageContentArray(system.content),
301	        ttl,
302	      ) as unknown as ChatCompletionMessageParam['content'];
303	    }
304	    return next;
305	  }
306	
307	  private buildResponseInput(
308	    userMessage: string,
309	    providerOptions?: Record<string, unknown>,
310	  ): EasyInputMessage[] {
311	    const override = providerOptions?.messages as
312	      | Array<{ role: string; content: unknown }>
313	      | undefined;
314	    const messages = Array.isArray(override) && override.length > 0
315	      ? override
316	      : [{ role: 'user', content: userMessage }];
317	
318	    return messages
319	      .filter((message) =>
320	        message.role === 'user' ||
321	        message.role === 'assistant' ||
322	        message.role === 'system',
323	      )
324	      .map((message) => ({
325	        role: message.role as EasyInputMessage['role'],
326	        content: this.stringifyResponseContent(message.content),
327	        type: 'message',
328	      }));
329	  }
330	
331	  private stringifyResponseContent(content: unknown): string {
332	    if (typeof content === 'string') return content;
333	    return normalizeMessageContentArray(content)
334	      .map((part) => String(part.text ?? ''))
335	      .filter(Boolean)
336	      .join('\n');
337	  }
338	}
339	
340	/**
341	 * Translate unified ReasoningEffort to Qwen / QwQ thinking parameters.
342	 *
343	 * Qwen3 thinking models accept `enable_thinking: true` (with optional
344	 * `thinking_budget` in tokens). DashScope's OpenAI-compat layer forwards
345	 * unknown top-level params verbatim, so we set them directly. Non-thinking
346	 * Qwen models silently ignore both fields.
347	 *
348	 *   off    → enable_thinking: false (forces fast path on QwQ / Qwen3-thinking)
349	 *   low    → enable_thinking: true, thinking_budget: 2048
350	 *   medium → enable_thinking: true, thinking_budget: 8192
351	 *   high   → enable_thinking: true, thinking_budget: 24576
352	 */
353	function qwenThinkingExtras(
354	  effort: ReasoningEffort | undefined,
355	): Record<string, unknown> {
356	  if (!effort) return {};
357	  if (effort === 'off') return { enable_thinking: false };
358	  const budget = effort === 'low' ? 2048 : effort === 'medium' ? 8192 : 24576;
359	  return { enable_thinking: true, thinking_budget: budget };
360	}
