1	/**
2	 * R5 — Deterministic quote validator.
3	 *
4	 * The provenance check from
5	 * docs/oracle/03-candidate-before-claim-validation.md. Pure function:
6	 * no DB, no I/O. Workers call this for every proposed evidence row
7	 * before the row is allowed to influence permanent claims.
8	 *
9	 * Verdict ladder (highest precedence first):
10	 *
11	 *   exact_match
12	 *     - The proposed quote appears VERBATIM in the source text exactly once,
13	 *       OR the model supplied offsets that decode to the exact quote.
14	 *
15	 *   normalized_match
16	 *     - The proposed quote appears verbatim in a *normalized* form of the
17	 *       source text. Used only when the caller supplied a non-empty
18	 *       NormalizationPolicy. The result records which normalization was
19	 *       applied so audits can replay the decision.
20	 *
21	 *   ambiguous
22	 *     - The proposed quote appears in the source MORE THAN ONCE and the
23	 *       model did NOT supply offsets to disambiguate. We refuse to pick.
24	 *
25	 *   failed
26	 *     - Any other condition (paraphrase, punctuation rewrite, synthesized
27	 *       quote spanning content the source does not contain, supplied
28	 *       offsets disagree with the source text, etc).
29	 *
30	 * Why no LLM-driven fuzzy match?
31	 *   Provenance must be deterministic. An LLM-graded "close enough" check
32	 *   would erase the auditability that makes The Oracle valuable.
33	 */
34	
35	import { normalize, methodForApplied } from './normalization';
36	import type {
37	  QuoteValidationResult,
38	  ValidateQuoteInput,
39	  ValidateSourcePointerInput,
40	  SourcePointerValidationResult,
41	} from './types';
42	import { STRICT_VERBATIM_POLICY } from './types';
43	
44	// ─────────────────────────────────────────────────────────────────────────
45	// Quote validation
46	// ─────────────────────────────────────────────────────────────────────────
47	
48	export function validateQuote(input: ValidateQuoteInput): QuoteValidationResult {
49	  const { sourceText, exactQuoteProvided, charStartProvided, charEndProvided } = input;
50	  const policy = input.normalizationPolicy ?? STRICT_VERBATIM_POLICY;
51	
52	  if (!exactQuoteProvided || exactQuoteProvided.length === 0) {
53	    return {
54	      verdict: 'failed',
55	      validationStatus: 'failed',
56	      validationMethod: 'none',
57	      failedCheckName: 'quote_exact_match',
58	      detail: 'exactQuoteProvided is empty.',
59	    };
60	  }
61	
62	  // ── 1. If the model supplied offsets, they're the ground truth.
63	  // We REQUIRE both offsets (not just one), they must be in order, and the
64	  // slice must equal the provided quote exactly.
65	  const hasStart = typeof charStartProvided === 'number';
66	  const hasEnd = typeof charEndProvided === 'number';
67	  if (hasStart !== hasEnd) {
68	    return {
69	      verdict: 'failed',
70	      validationStatus: 'failed',
71	      validationMethod: 'none',
72	      failedCheckName: 'quote_offsets_match',
73	      detail: 'charStartProvided and charEndProvided must be supplied together or not at all.',
74	    };
75	  }
76	  if (hasStart && hasEnd) {
77	    if (charStartProvided! < 0 || charEndProvided! < 0) {
78	      return {
79	        verdict: 'failed',
80	        validationStatus: 'failed',
81	        validationMethod: 'verbatim_offset_match',
82	        failedCheckName: 'quote_offsets_match',
83	        detail: 'Provided offsets are negative.',
84	      };
85	    }
86	    if (charEndProvided! < charStartProvided!) {
87	      return {
88	        verdict: 'failed',
89	        validationStatus: 'failed',
90	        validationMethod: 'verbatim_offset_match',
91	        failedCheckName: 'quote_offsets_match',
92	        detail: 'Provided charEnd precedes charStart.',
93	      };
94	    }
95	    if (charEndProvided! > sourceText.length) {
96	      return {
97	        verdict: 'failed',
98	        validationStatus: 'failed',
99	        validationMethod: 'verbatim_offset_match',
100	        failedCheckName: 'quote_offsets_match',
101	        detail: 'Provided charEnd extends past the source text.',
102	      };
103	    }
104	    const slice = sourceText.slice(charStartProvided, charEndProvided);
105	    if (slice === exactQuoteProvided) {
106	      return {
107	        verdict: 'exact_match',
108	        validationStatus: 'exact_match',
109	        validationMethod: 'verbatim_offset_match',
110	        validatedExactQuote: slice,
111	        validatedCharStart: charStartProvided,
112	        validatedCharEnd: charEndProvided,
113	        detail: 'Quote matched at provided offsets.',
114	      };
115	    }
116	    return {
117	      verdict: 'failed',
118	      validationStatus: 'failed',
119	      validationMethod: 'verbatim_offset_match',
120	      failedCheckName: 'quote_offsets_match',
121	      detail: `Source text at [${charStartProvided}, ${charEndProvided}] does not equal exactQuoteProvided. Got: ${JSON.stringify(
122	        slice.slice(0, 200),
123	      )}`,
124	    };
125	  }
126	
127	  // ── 2. No offsets supplied. Try verbatim .indexOf scan.
128	  const firstIdx = sourceText.indexOf(exactQuoteProvided);
129	  if (firstIdx !== -1) {
130	    const secondIdx = sourceText.indexOf(exactQuoteProvided, firstIdx + 1);
131	    if (secondIdx !== -1) {
132	      return {
133	        verdict: 'ambiguous',
134	        validationStatus: 'ambiguous',
135	        validationMethod: 'verbatim_includes',
136	        failedCheckName: 'quote_exact_match',
137	        detail: 'Quote appears more than once in source. Model must supply explicit offsets.',
138	      };
139	    }
140	    return {
141	      verdict: 'exact_match',
142	      validationStatus: 'exact_match',
143	      validationMethod: 'verbatim_includes',
144	      validatedExactQuote: exactQuoteProvided,
145	      validatedCharStart: firstIdx,
146	      validatedCharEnd: firstIdx + exactQuoteProvided.length,
147	      detail: 'Quote matched via single-occurrence verbatim scan.',
148	    };
149	  }
150	
151	  // ── 3. Verbatim failed. If the caller enabled any normalization, retry
152	  // against the normalized form of BOTH the source and the quote.
153	  const policyEnabled =
154	    !!policy.allowCRLF ||
155	    !!policy.allowSmartQuotes ||
156	    !!policy.allowWhitespaceCollapse ||
157	    !!policy.allowLeadingTrailingTrim;
158	  if (policyEnabled) {
159	    const normSource = normalize(sourceText, policy);
160	    const normQuote = normalize(exactQuoteProvided, policy);
161	    const normFirstIdx = normSource.text.indexOf(normQuote.text);
162	    if (normFirstIdx !== -1) {
163	      const normSecondIdx = normSource.text.indexOf(normQuote.text, normFirstIdx + 1);
164	      if (normSecondIdx !== -1) {
165	        return {
166	          verdict: 'ambiguous',
167	          validationStatus: 'ambiguous',
168	          validationMethod: methodForApplied(normSource.applied.concat(normQuote.applied)),
169	          failedCheckName: 'quote_exact_match',
170	          detail:
171	            'Quote appears more than once after normalization. Model must supply explicit offsets.',
172	        };
173	      }
174	      // Normalized match. The validatedExactQuote we report is the substring
175	      // of the ORIGINAL source covering the same logical span. For a strict
176	      // implementation we'd need to map normalized offsets back to original
177	      // offsets — that's nontrivial when whitespace was collapsed. As a
178	      // conservative compromise we report the normalized quote as validated.
179	      // Workers that need exact source bytes must use strict verbatim mode.
180	      return {
181	        verdict: 'normalized_match',
182	        validationStatus: 'normalized_match',
183	        validationMethod: methodForApplied(normSource.applied.concat(normQuote.applied)),
184	        validatedExactQuote: normQuote.text,
185	        validatedCharStart: normFirstIdx,
186	        validatedCharEnd: normFirstIdx + normQuote.text.length,
187	        detail:
188	          'Quote matched after normalization. Source/quote offsets are against the normalized form.',
189	      };
190	    }
191	  }
192	
193	  // ── 4. Fuzzy fallback (opt-in via allowFuzzy). For messy spoken transcripts
194	  // the model paraphrases disfluent speech, so verbatim/normalized matching
195	  // fails even when the claim genuinely came from this utterance. We accept the
196	  // match when the quote's content tokens sufficiently overlap the source, and
197	  // anchor the evidence to the REAL source text (the full utterance) rather than
198	  // the model's paraphrase — provenance still points at actual spoken words.
199	  // This is a deterministic token check (no LLM grader). See
200	  // DECISIONS.md D-transcript-fuzzy-quote.
201	  if (input.allowFuzzy) {
202	    const minOverlap = input.fuzzyMinOverlap ?? 0.5;
203	    const tokenize = (s: string): string[] => s.toLowerCase().match(/[a-z0-9']+/g) ?? [];
204	    const quoteTokens = tokenize(exactQuoteProvided);
205	    const sourceTokens = new Set(tokenize(sourceText));
206	    if (quoteTokens.length >= 4 && sourceTokens.size > 0) {
207	      const present = quoteTokens.filter((t) => sourceTokens.has(t)).length;
208	      const overlap = present / quoteTokens.length;
209	      if (overlap >= minOverlap) {
210	        return {
211	          verdict: 'normalized_match',
212	          validationStatus: 'normalized_match',
213	          validationMethod: 'fuzzy_token_overlap',
214	          validatedExactQuote: sourceText,
215	          validatedCharStart: 0,
216	          validatedCharEnd: sourceText.length,
217	          detail: `Fuzzy match: ${present}/${quoteTokens.length} quote tokens (${Math.round(
218	            overlap * 100,
219	          )}%) present in the source utterance; evidence anchored to the full source utterance.`,
220	        };
221	      }
222	    }
223	  }
224	
225	  return {
226	    verdict: 'failed',
227	    validationStatus: 'failed',
228	    validationMethod: 'verbatim_includes',
229	    failedCheckName: 'quote_exact_match',
230	    detail: 'exactQuoteProvided was not found in sourceText.',
231	  };
232	}
233	
234	// ─────────────────────────────────────────────────────────────────────────
235	// Source-pointer validation
236	// Mirrors extraction_candidate_evidence_source_check from
237	// migrations/sql/13_extraction_constraints.sql.
238	// ─────────────────────────────────────────────────────────────────────────
239	
240	export function validateSourcePointer(
241	  input: ValidateSourcePointerInput,
242	): SourcePointerValidationResult {
243	  const { sourceType, sourceMessageId, sourceDocumentChunkId, sourceExternalRecordId, createdByEmployeeId } =
244	    input;
245	
246	  switch (sourceType) {
247	    case 'message':
248	      if (!sourceMessageId) {
249	        return {
250	          ok: false,
251	          failedCheckName: 'source_type_valid',
252	          detail: 'source_type=message requires non-null source_message_id.',
253	        };
254	      }
255	      return { ok: true, detail: 'message source pointer present.' };
256	
257	    case 'document_chunk':
258	      if (!sourceDocumentChunkId) {
259	        return {
260	          ok: false,
261	          failedCheckName: 'source_type_valid',
262	          detail: 'source_type=document_chunk requires non-null source_document_chunk_id.',
263	        };
264	      }
265	      return { ok: true, detail: 'document_chunk source pointer present.' };
266	
267	    case 'external_system':
268	      if (!sourceExternalRecordId) {
269	        return {
270	          ok: false,
271	          failedCheckName: 'source_type_valid',
272	          detail: 'source_type=external_system requires non-null source_external_record_id.',
273	        };
274	      }
275	      return { ok: true, detail: 'external_system source pointer present.' };
276	
277	    case 'manual_admin':
278	      if (!createdByEmployeeId) {
279	        return {
280	          ok: false,
281	          failedCheckName: 'source_type_valid',
282	          detail: 'source_type=manual_admin requires non-null created_by_employee_id.',
283	        };
284	      }
285	      return { ok: true, detail: 'manual_admin source pointer present.' };
286	
287	    default:
288	      return {
289	        ok: false,
290	        failedCheckName: 'source_type_valid',
291	        detail: `unknown source type: ${sourceType}`,
292	      };
293	  }
294	}
