1	/**
2	 * R5.5 — Taxonomy validator.
3	 *
4	 * Pure function. Given a candidate's proposed top-domain IDs and entity
5	 * references, plus the relevant registry slices, returns:
6	 *
7	 *   - resolved entity assignments (ready for claim_entities inserts)
8	 *   - entity proposals to stage in entity_proposals
9	 *   - validation failures that should hold the candidate
10	 *
11	 * Workers call this after R5's quote validation and before R5's
12	 * decidePromotion, then feed the results into decidePromotion via the
13	 * extended snapshot shape.
14	 *
15	 * Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R5.5 task 5.
16	 */
17	
18	import type { EntityType, ValidationCheckName } from '@oracle/shared';
19	import { resolveEntity, type RegistryEntity, type ResolveEntityResult } from './entity-resolver';
20	
21	// ─────────────────────────────────────────────────────────────────────────
22	// Inputs / outputs
23	// ─────────────────────────────────────────────────────────────────────────
24	
25	export interface ProposedEntityReference {
26	  entityType: EntityType;
27	  rawString: string;
28	}
29	
30	export interface ValidateTaxonomyInput {
31	  /** Top-domain IDs proposed by the model. */
32	  proposedTopDomainIds: string[];
33	  /** Currently-active top-domain IDs from `knowledge_top_domains`. */
34	  activeTopDomainIds: string[];
35	  /** Entity references the model surfaced. */
36	  proposedEntities: ProposedEntityReference[];
37	  /** The entity registry slice the worker fetched (see entity-resolver). */
38	  entityRegistry: RegistryEntity[];
39	}
40	
41	export interface ResolvedEntityAssignment {
42	  entityId: string;
43	  entityType: EntityType;
44	  canonicalValue: string;
45	  matchKind: 'canonical_exact' | 'alias';
46	  /** The raw string the model surfaced, kept for audit. */
47	  rawString: string;
48	}
49	
50	export interface EntityProposalToCreate {
51	  proposedEntityType: EntityType;
52	  proposedCanonicalValue: string;
53	  rawString: string;
54	  /** Why this proposal was created. */
55	  reason: 'unknown_entity' | 'type_mismatch_correction';
56	  /** When type_mismatch, the entity that matched under the wrong type. */
57	  matchedEntityId?: string;
58	  matchedEntityType?: EntityType;
59	}
60	
61	export interface TaxonomyValidationFailure {
62	  failedCheckName: ValidationCheckName;
63	  detail: string;
64	  /** Optional structured payload for `extraction_validation_results.metadata_json`. */
65	  metadata?: unknown;
66	}
67	
68	export interface TaxonomyValidationResult {
69	  ok: boolean;
70	  /** Top-domain IDs the worker should write to claim_top_domains. */
71	  validTopDomainIds: string[];
72	  /** Entities the worker should write to claim_entities. */
73	  resolvedEntities: ResolvedEntityAssignment[];
74	  /** Entity proposals to insert before promotion (best-effort; admin reviews later). */
75	  entityProposalsToCreate: EntityProposalToCreate[];
76	  /** Failures that should block promotion. */
77	  failures: TaxonomyValidationFailure[];
78	  /**
79	   * If true, the candidate has unresolved entity references but ALL of
80	   * them are merely unknown (not type-mismatches and not ambiguous).
81	   * Workers may choose to stage the proposals and still hold the candidate
82	   * as `pending_validation` rather than reject.
83	   */
84	  blockedByOnlyUnknownEntities: boolean;
85	  /**
86	   * Optional short human-readable summary of the failure mix, suitable
87	   * for `extraction_validation_results.detail` and for surfacing in the
88	   * promotion decision's reject message.
89	   */
90	  failureSummary?: string;
91	}
92	
93	// ─────────────────────────────────────────────────────────────────────────
94	// Validator
95	// ─────────────────────────────────────────────────────────────────────────
96	
97	export function validateTaxonomy(input: ValidateTaxonomyInput): TaxonomyValidationResult {
98	  const { proposedTopDomainIds, activeTopDomainIds, proposedEntities, entityRegistry } = input;
99	
100	  const failures: TaxonomyValidationFailure[] = [];
101	  const resolvedEntities: ResolvedEntityAssignment[] = [];
102	  const entityProposalsToCreate: EntityProposalToCreate[] = [];
103	  let blockedByOnlyUnknownEntities = false;
104	
105	  // ── 1. Top-domain validation
106	  const activeSet = new Set(activeTopDomainIds);
107	  const validTopDomainIds: string[] = [];
108	  const unknownTopDomains: string[] = [];
109	  for (const id of proposedTopDomainIds) {
110	    if (activeSet.has(id)) validTopDomainIds.push(id);
111	    else unknownTopDomains.push(id);
112	  }
113	
114	  if (proposedTopDomainIds.length === 0) {
115	    failures.push({
116	      failedCheckName: 'domain_valid',
117	      detail: 'Candidate proposed no top-domain IDs.',
118	    });
119	  }
120	  if (unknownTopDomains.length > 0) {
121	    failures.push({
122	      failedCheckName: 'domain_valid',
123	      detail: `Proposed top-domain IDs not present in knowledge_top_domains: ${unknownTopDomains.join(', ')}. Candidate is held; admin should create or remap the missing domain via taxonomy_proposals.`,
124	      metadata: { unknownTopDomains, activeTopDomainIdsSampled: activeTopDomainIds.slice(0, 12) },
125	    });
126	  }
127	
128	  // ── 2. Entity resolution
129	  let unknownCount = 0;
130	  let nonUnknownFailureCount = 0;
131	  for (const ref of proposedEntities) {
132	    const res: ResolveEntityResult = resolveEntity({
133	      proposedEntityType: ref.entityType,
134	      rawString: ref.rawString,
135	      registry: entityRegistry,
136	    });
137	    switch (res.outcome) {
138	      case 'resolved':
139	        resolvedEntities.push({
140	          entityId: res.entityId,
141	          entityType: res.entityType,
142	          canonicalValue: res.canonicalValue,
143	          matchKind: res.matchKind,
144	          rawString: ref.rawString,
145	        });
146	        break;
147	
148	      case 'unknown':
149	        unknownCount += 1;
150	        entityProposalsToCreate.push({
151	          proposedEntityType: res.proposal.proposedEntityType,
152	          proposedCanonicalValue: res.proposal.proposedCanonicalValue,
153	          rawString: res.proposal.rawString,
154	          reason: 'unknown_entity',
155	        });
156	        failures.push({
157	          failedCheckName: 'source_type_valid',
158	          detail: `Entity "${ref.rawString}" (type=${ref.entityType}) does not resolve in the registry. Staged as entity_proposals; candidate is held until reviewed.`,
159	        });
160	        break;
161	
162	      case 'type_mismatch':
163	        nonUnknownFailureCount += 1;
164	        entityProposalsToCreate.push({
165	          proposedEntityType: res.proposedEntityType,
166	          proposedCanonicalValue: ref.rawString.trim(),
167	          rawString: ref.rawString,
168	          reason: 'type_mismatch_correction',
169	          matchedEntityId: res.matchedEntityId,
170	          matchedEntityType: res.matchedEntityType,
171	        });
172	        failures.push({
173	          failedCheckName: 'source_type_valid',
174	          detail:
175	            `Entity "${ref.rawString}" was proposed as ${ref.entityType} but resolves in the registry as ${res.matchedEntityType} (canonical "${res.matchedCanonicalValue}"). ` +
176	            `The candidate is held; this is most likely a licensor-vs-vendor confusion that needs admin attention.`,
177	          metadata: {
178	            proposedEntityType: ref.entityType,
179	            matchedEntityType: res.matchedEntityType,
180	            matchedEntityId: res.matchedEntityId,
181	            matchedCanonicalValue: res.matchedCanonicalValue,
182	          },
183	        });
184	        break;
185	
186	      case 'ambiguous':
187	        nonUnknownFailureCount += 1;
188	        failures.push({
189	          failedCheckName: 'source_type_valid',
190	          detail:
191	            `Entity "${ref.rawString}" (type=${ref.entityType}) is ambiguous — matches multiple registry rows. Worker must disambiguate before promotion.`,
192	          metadata: { candidates: res.candidates },
193	        });
194	        break;
195	    }
196	  }
197	
198	  blockedByOnlyUnknownEntities =
199	    failures.length > 0 &&
200	    failures.every((f) => f.failedCheckName === 'source_type_valid') &&
201	    nonUnknownFailureCount === 0 &&
202	    unknownCount > 0 &&
203	    unknownTopDomains.length === 0;
204	
205	  return {
206	    ok: failures.length === 0,
207	    validTopDomainIds,
208	    resolvedEntities,
209	    entityProposalsToCreate,
210	    failures,
211	    blockedByOnlyUnknownEntities,
212	  };
213	}
