1	/**
2	 * R5 — Candidate promotion service.
3	 *
4	 * Concurrency-locked, idempotent promotion from staging
5	 * (`extraction_candidates` + `extraction_candidate_evidence`) to permanent
6	 * tables (`claims` + `claim_top_domains` + `claim_evidence`).
7	 *
8	 * Per docs/oracle/03-candidate-before-claim-validation.md
9	 * "Candidate promotion transaction (Concurrency Locked)":
10	 *
11	 *   1. Begin transaction.
12	 *   2. Acquire advisory lock on hashtextextended(candidateHash, 0).
13	 *   3. Confirm candidate status is 'validated' and not already promoted.
14	 *   4. Check for an existing claim with the same hash. If found, append
15	 *      THIS candidate's evidence to that claim instead of inserting a
16	 *      duplicate, and mark this candidate as 'duplicate'.
17	 *   5. Otherwise insert claims + claim_top_domains + claim_evidence atomically.
18	 *   6. Update candidate to 'promoted' (or 'duplicate') with timestamps.
19	 *   7. Commit.
20	 *
21	 * The transactional executor is wired to Drizzle in
22	 * `runPromotionInTransaction` below. The DECISION logic — what to insert,
23	 * what to append, what to reject — is extracted into `decidePromotion` as
24	 * a pure function so the 6 R5 tests can exercise it without a real DB.
25	 */
26	
27	import type { EntityType, EvidenceSourceType } from '@oracle/shared';
28	import type { EntityProposalToCreate, ResolvedEntityAssignment } from './taxonomy-validator';
29	
30	// ─────────────────────────────────────────────────────────────────────────
31	// Decision shapes — what the promoter sees, what it decides to do.
32	// ─────────────────────────────────────────────────────────────────────────
33	
34	/** Claim-level metadata the model surfaced (per R5.5). Goes into claim_metadata. */
35	export interface CandidateMetadata {
36	  processStage?: string | null;
37	  department?: string | null;
38	  geography?: string | null;
39	  documentClass?: string | null;
40	  effectiveFrom?: Date | null;
41	  effectiveUntil?: Date | null;
42	}
43	
44	export interface CandidateSnapshot {
45	  /** Hashed canonical representation of the candidate (see candidate-hash.ts). */
46	  candidateHash: string;
47	
48	  /** From `extraction_candidates`. */
49	  candidate: {
50	    id: string;
51	    status: string;
52	    summary: string;
53	    claimType: string;
54	    impactScore: number;
55	    confidenceScore?: number;
56	    domains: string[];
57	    promotedToClaimId?: string | null;
58	  };
59	
60	  /** From `extraction_candidate_evidence`. Only rows with validationStatus in (exact_match, normalized_match). */
61	  validatedEvidence: Array<{
62	    id: string;
63	    sourceType: EvidenceSourceType;
64	    sourceMessageId?: string | null;
65	    sourceDocumentChunkId?: string | null;
66	    sourceExternalRecordId?: string | null;
67	    assertedByEmployeeId?: string | null;
68	    uploadedByEmployeeId?: string | null;
69	    createdByEmployeeId?: string | null;
70	    validatedExactQuote: string;
71	    validatedCharStart: number;
72	    validatedCharEnd: number;
73	    pageNumber?: number | null;
74	    confidence?: number | null;
75	    /** R5.5 — surfaced per evidence row when the model could infer them. */
76	    documentClass?: string | null;
77	    processStage?: string | null;
78	  }>;
79	
80	  /**
81	   * R5.5 — Taxonomy validation result (from `validateTaxonomy`). Optional
82	   * for backward compatibility with R5 callers that don't run the
83	   * taxonomy validator yet.
84	   *
85	   * When present:
86	   *  - `validTopDomainIds` replaces `candidate.domains` as the set of
87	   *    top-domain rows we'll actually write.
88	   *  - `resolvedEntities` becomes the claim_entities inserts.
89	   *  - `entityProposalsToCreate` are staged BEFORE the promotion runs.
90	   *  - `ok: false` blocks promotion unless every failure is an unknown entity
91	   *    proposal (`blockedByOnlyUnknownEntities`), in which case proposals are
92	   *    staged and the claim can still be written with validated domains.
93	   */
94	  taxonomy?: {
95	    ok: boolean;
96	    validTopDomainIds: string[];
97	    resolvedEntities: ResolvedEntityAssignment[];
98	    entityProposalsToCreate: EntityProposalToCreate[];
99	    blockedByOnlyUnknownEntities?: boolean;
100	    failureSummary?: string;
101	  };
102	
103	  /** R5.5 — Claim-level metadata to write to claim_metadata. */
104	  metadata?: CandidateMetadata;
105	
106	  /**
107	   * The claim — if any — that the candidate's hash matches. The promoter
108	   * checks this INSIDE the transaction so a worker racing for the lock
109	   * sees the latest committed state.
110	   */
111	  existingClaimWithSameHash?: { claimId: string } | null;
112	}
113	
114	/** R5.5 — Entity tag assignments to write to claim_entities. */
115	export interface EntityAssignment {
116	  entityId: string;
117	  entityType: EntityType;
118	  canonicalValue: string;
119	}
120	
121	export type PromotionDecision =
122	  | {
123	      kind: 'insert_new_claim';
124	      /** Stable hash this claim will be associated with via the candidate. */
125	      candidateHash: string;
126	      claim: {
127	        claimType: string;
128	        summary: string;
129	        impactScore: number;
130	        confidenceScore?: number;
131	        // R3.5+: status is now a varchar (per oracle_master_spec §6.6),
132	        // but the existing claims table still uses claimStatusEnum until
133	        // R6 migrates the schema. Promotion inserts 'pending_review' — the
134	        // admin queue does the final approval.
135	        status: 'pending_review';
136	      };
137	      topDomainAssignments: Array<{ topDomainId: string; assignmentReason: 'extraction' }>;
138	      /** R5.5 — claim_entities rows to insert. Empty when the candidate had no entities. */
139	      entityAssignments: EntityAssignment[];
140	      /** R5.5 — claim_metadata row to insert. Undefined when no metadata was surfaced. */
141	      metadata?: CandidateMetadata;
142	      /** R5.5 — entity_proposals rows to stage before the promotion runs. */
143	      entityProposalsToStage: EntityProposalToCreate[];
144	      evidenceRows: CandidateSnapshot['validatedEvidence'];
145	      candidateUpdate: { status: 'promoted'; setPromotedToClaimId: true };
146	    }
147	  | {
148	      kind: 'append_to_existing_claim';
149	      candidateHash: string;
150	      existingClaimId: string;
151	      /** R5.5 — entity tags to merge onto the existing claim. */
152	      entityAssignments: EntityAssignment[];
153	      /** R5.5 — entity_proposals to stage even when the candidate is a duplicate. */
154	      entityProposalsToStage: EntityProposalToCreate[];
155	      evidenceRows: CandidateSnapshot['validatedEvidence'];
156	      candidateUpdate: { status: 'duplicate'; setDuplicateOfClaimId: string };
157	    }
158	  | {
159	      kind: 'reject';
160	      reason:
161	        | 'not_validated'
162	        | 'already_promoted'
163	        | 'no_validated_evidence'
164	        | 'no_domains'
165	        | 'taxonomy_invalid'
166	        | 'invalid_state';
167	      detail: string;
168	      /** R5.5 — even rejected candidates may surface entity proposals worth staging. */
169	      entityProposalsToStage?: EntityProposalToCreate[];
170	    };
171	
172	// ─────────────────────────────────────────────────────────────────────────
173	// Pure decision function — testable without a DB.
174	// ─────────────────────────────────────────────────────────────────────────
175	
176	export function decidePromotion(snapshot: CandidateSnapshot): PromotionDecision {
177	  const {
178	    candidate,
179	    validatedEvidence,
180	    candidateHash,
181	    existingClaimWithSameHash,
182	    taxonomy,
183	    metadata,
184	  } = snapshot;
185	
186	  // Entity proposals are worth surfacing even when we reject — admin can
187	  // review the proposals separately. We thread them through every branch.
188	  const entityProposalsToStage = taxonomy?.entityProposalsToCreate ?? [];
189	
190	  // Idempotency: re-running the promoter on an already-promoted candidate
191	  // returns 'already_promoted' without trying to insert anything.
192	  if (candidate.status === 'promoted') {
193	    return {
194	      kind: 'reject',
195	      reason: 'already_promoted',
196	      detail: `Candidate ${candidate.id} is already promoted to claim ${candidate.promotedToClaimId ?? '<unknown>'}.`,
197	      entityProposalsToStage,
198	    };
199	  }
200	
201	  // The candidate must be 'validated' before promotion. Anything else
202	  // (pending_validation, validation_failed, rejected, *_sensitive) gets
203	  // rejected here — the only way out of those states is review, not promotion.
204	  if (candidate.status !== 'validated') {
205	    return {
206	      kind: 'reject',
207	      reason: 'not_validated',
208	      detail: `Candidate ${candidate.id} has status "${candidate.status}", must be "validated" to promote.`,
209	      entityProposalsToStage,
210	    };
211	  }
212	
213	  if (validatedEvidence.length === 0) {
214	    return {
215	      kind: 'reject',
216	      reason: 'no_validated_evidence',
217	      detail: `Candidate ${candidate.id} has no evidence rows with validation_status in (exact_match, normalized_match).`,
218	      entityProposalsToStage,
219	    };
220	  }
221	
222	  // R5.5: hard taxonomy failures block promotion. Unknown-only entity
223	  // references still stage proposals, but do not hold an otherwise
224	  // evidence-backed claim; the claim can be useful with domain tags while
225	  // admins clean up optional entity tags later.
226	  if (taxonomy && !taxonomy.ok && !taxonomy.blockedByOnlyUnknownEntities) {
227	    return {
228	      kind: 'reject',
229	      reason: 'taxonomy_invalid',
230	      detail:
231	        `Candidate ${candidate.id} failed taxonomy validation. ` +
232	        (taxonomy.failureSummary ??
233	          'See extraction_validation_results for the per-check breakdown.'),
234	      entityProposalsToStage,
235	    };
236	  }
237	
238	  // The effective top-domain ID list is the taxonomy-validated subset when
239	  // available, otherwise the raw candidate.domains (R5 callers).
240	  const effectiveTopDomainIds = taxonomy ? taxonomy.validTopDomainIds : candidate.domains;
241	  if (!effectiveTopDomainIds || effectiveTopDomainIds.length === 0) {
242	    return {
243	      kind: 'reject',
244	      reason: 'no_domains',
245	      detail: `Candidate ${candidate.id} has no valid top-domain IDs after taxonomy validation.`,
246	      entityProposalsToStage,
247	    };
248	  }
249	
250	  const entityAssignments: EntityAssignment[] = (taxonomy?.resolvedEntities ?? []).map((e) => ({
251	    entityId: e.entityId,
252	    entityType: e.entityType,
253	    canonicalValue: e.canonicalValue,
254	  }));
255	
256	  // Duplicate detection. The advisory lock means we're the only writer
257	  // holding this hash; if there's still an existing claim row, another
258	  // worker won the race already and we append our evidence to theirs.
259	  if (existingClaimWithSameHash) {
260	    return {
261	      kind: 'append_to_existing_claim',
262	      candidateHash,
263	      existingClaimId: existingClaimWithSameHash.claimId,
264	      entityAssignments,
265	      entityProposalsToStage,
266	      evidenceRows: validatedEvidence,
267	      candidateUpdate: {
268	        status: 'duplicate',
269	        setDuplicateOfClaimId: existingClaimWithSameHash.claimId,
270	      },
271	    };
272	  }
273	
274	  // Happy path: insert a new claim, the top-domain rows, the entity
275	  // tag rows, the metadata row, and the evidence rows, atomically.
276	  return {
277	    kind: 'insert_new_claim',
278	    candidateHash,
279	    claim: {
280	      claimType: candidate.claimType,
281	      summary: candidate.summary,
282	      impactScore: candidate.impactScore,
283	      confidenceScore: candidate.confidenceScore,
284	      status: 'pending_review',
285	    },
286	    topDomainAssignments: effectiveTopDomainIds.map((id) => ({
287	      topDomainId: id,
288	      assignmentReason: 'extraction',
289	    })),
290	    entityAssignments,
291	    metadata: metadata && hasAnyMetadata(metadata) ? metadata : undefined,
292	    entityProposalsToStage,
293	    evidenceRows: validatedEvidence,
294	    candidateUpdate: { status: 'promoted', setPromotedToClaimId: true },
295	  };
296	}
297	
298	/** Internal — true if at least one field in the metadata payload is non-null. */
299	function hasAnyMetadata(m: CandidateMetadata): boolean {
300	  return Boolean(
301	    m.processStage ||
302	    m.department ||
303	    m.geography ||
304	    m.documentClass ||
305	    m.effectiveFrom ||
306	    m.effectiveUntil,
307	  );
308	}
309	
310	// ─────────────────────────────────────────────────────────────────────────
311	// Executor stub.
312	//
313	// The full Drizzle wiring lands when R6 actually calls into this from the
314	// claim-extraction worker. The stub below documents the exact SQL surface
315	// the executor will use so reviewers can audit the transactional shape
316	// without grepping for it later.
317	// ─────────────────────────────────────────────────────────────────────────
318	
319	/**
320	 * Pseudo-code the executor MUST follow when R6 wires this up to Drizzle.
321	 * The pure `decidePromotion` is the spec; this is the runbook for turning
322	 * that decision into SQL.
323	 *
324	 * ```ts
325	 * await db.transaction(async (tx) => {
326	 *   // 1. Advisory lock keyed on the candidate hash.
327	 *   //    pg_try_advisory_xact_lock returns FALSE if another tx holds it —
328	 *   //    the worker should back off and retry rather than block forever.
329	 *   const lockRes = await tx.execute(
330	 *     sql`SELECT pg_try_advisory_xact_lock(hashtextextended(${candidateHash}, 0)) AS locked`
331	 *   );
332	 *   if (!lockRes[0].locked) throw new AdvisoryLockBusyError(candidateHash);
333	 *
334	 *   // 2. Re-read the candidate state INSIDE the lock so we see the latest
335	 *   //    committed view of the world.
336	 *   const candidate = await tx.query.extractionCandidates.findFirst({
337	 *     where: eq(extractionCandidates.id, candidateId),
338	 *     with: { evidence: true },
339	 *   });
340	 *
341	 *   // 3. Look for an existing claim with the same hash. We could store the
342	 *   //    candidate hash on claims directly, or compute it on the fly from a
343	 *   //    join across claim_top_domains and claim_evidence. R6 will pick the
344	 *   //    cheaper option after evals; for now we recommend a hash column on
345	 *   //    claims with a UNIQUE index for O(1) lookup.
346	 *
347	 *   // 4. Run the pure decider.
348	 *   const decision = decidePromotion(snapshot);
349	 *
350	 *   // 5. Apply the decision.
351	 *   switch (decision.kind) {
352	 *     case 'insert_new_claim': {
353	 *       const claimRow = await tx.insert(claims).values(decision.claim).returning();
354	 *       await tx.insert(claimTopDomains).values(
355	 *         decision.topDomainAssignments.map((a) => ({ claimId: claimRow.id, ...a }))
356	 *       );
357	 *       await tx.insert(claimEvidence).values(
358	 *         decision.evidenceRows.map((e) => ({ claimId: claimRow.id, ...e }))
359	 *       );
360	 *       await tx.update(extractionCandidates).set({
361	 *         status: 'promoted',
362	 *         promotedToClaimId: claimRow.id,
363	 *         promotedAt: new Date(),
364	 *       }).where(eq(extractionCandidates.id, candidateId));
365	 *       break;
366	 *     }
367	 *     case 'append_to_existing_claim': {
368	 *       await tx.insert(claimEvidence).values(
369	 *         decision.evidenceRows.map((e) => ({ claimId: decision.existingClaimId, ...e }))
370	 *       );
371	 *       await tx.update(extractionCandidates).set({
372	 *         status: 'duplicate',
373	 *         duplicateOfClaimId: decision.existingClaimId,
374	 *         promotedAt: new Date(),
375	 *       }).where(eq(extractionCandidates.id, candidateId));
376	 *       break;
377	 *     }
378	 *     case 'reject': {
379	 *       await tx.insert(extractionValidationResults).values({
380	 *         candidateId,
381	 *         checkName: 'promotion_transaction',
382	 *         status: 'fail',
383	 *         detail: `${decision.reason}: ${decision.detail}`,
384	 *       });
385	 *       break;
386	 *     }
387	 *   }
388	 * });
389	 * ```
390	 *
391	 * R6 lifts that runbook into a real function. R5 ships the decider and
392	 * the candidate hash so the runbook is just SQL plumbing.
393	 */
394	export const PROMOTION_TRANSACTION_RUNBOOK = 'See JSDoc in promote-candidate.ts';
