1	/**
2	 * ModelRouter — given a routeId, picks the correct provider adapter and
3	 * dispatches the call. Handles fallback dispatch when a primary route
4	 * fails with a known transient or schema-validation error.
5	 *
6	 * The router does NOT pick which route to use for a given task — that
7	 * decision belongs to whoever calls OracleAIClient (chat route, extraction
8	 * worker, etc.). The router only:
9	 *
10	 *   - resolves a routeId → adapter
11	 *   - executes the call
12	 *   - on failure, optionally dispatches the configured Fallback route
13	 *
14	 * Per docs/oracle/01-model-roles-and-routes.md "Model routing rules".
15	 */
16	
17	import type {
18	  OracleObjectResult,
19	  OraclePromptPlan,
20	  OracleTaskType,
21	  OracleTextResult,
22	} from '../client/types';
23	import {
24	  getOracleRoute,
25	  resolveModelRoute,
26	  type OracleModelRole,
27	  type OracleModelRoute,
28	  type OracleProvider,
29	} from '../routes';
30	import {
31	  ProviderAdapterNotImplementedError,
32	  type OracleProviderAdapter,
33	} from '../providers/types';
34	
35	export type ProviderAdapterMap = Partial<Record<OracleProvider, OracleProviderAdapter>>;
36	
37	export interface ModelRouterOptions {
38	  adapters: ProviderAdapterMap;
39	  /**
40	   * If true, when the primary adapter throws a transient or schema error,
41	   * the router will dispatch to the route's fallbackRouteId. Default true.
42	   */
43	  fallbackOnError?: boolean;
44	}
45	
46	export class UnknownRouteError extends Error {
47	  constructor(routeId: string) {
48	    super(
49	      `No OracleModelRoute found for routeId "${routeId}". Use a catalog routeId or a supported provider/model id.`,
50	    );
51	    this.name = 'UnknownRouteError';
52	  }
53	}
54	
55	export class NoAdapterRegisteredError extends Error {
56	  constructor(provider: OracleProvider) {
57	    super(
58	      `No adapter registered for provider "${provider}". Pass it to ModelRouter via options.adapters.`,
59	    );
60	    this.name = 'NoAdapterRegisteredError';
61	  }
62	}
63	
64	export class ModelRouter {
65	  private readonly adapters: ProviderAdapterMap;
66	  private readonly fallbackOnError: boolean;
67	
68	  constructor(opts: ModelRouterOptions) {
69	    this.adapters = opts.adapters;
70	    this.fallbackOnError = opts.fallbackOnError ?? true;
71	  }
72	
73	  /**
74	   * Resolve a route + adapter pair, or throw with a descriptive error.
75	   *
76	   * Static catalog routes are preferred. If the routeId is an admin-selected
77	   * provider/model id such as "qwen/qwen3.7-plus", synthesize the same dynamic
78	   * route shape produced by resolveRouteFromSettings().
79	   */
80	  resolve(routeId: string, taskType?: OracleTaskType): { route: OracleModelRoute; adapter: OracleProviderAdapter } {
81	    const route = this.resolveRoute(routeId, taskType);
82	    const adapter = this.adapters[route.provider];
83	    if (!adapter) throw new NoAdapterRegisteredError(route.provider);
84	    return { route, adapter };
85	  }
86	
87	  async generateText(
88	    plan: OraclePromptPlan,
89	    providerOptions?: Record<string, unknown>,
90	  ): Promise<OracleTextResult> {
91	    return this.dispatch(plan, (adapter, route) =>
92	      adapter.generateText({ plan, route, providerOptions }),
93	    );
94	  }
95	
96	  async generateObject<TSchema, TOutput>(
97	    plan: OraclePromptPlan,
98	    schema: TSchema,
99	    providerOptions?: Record<string, unknown>,
100	  ): Promise<OracleObjectResult<TOutput>> {
101	    return this.dispatch(plan, (adapter, route) =>
102	      adapter.generateObject<TSchema, TOutput>({ plan, route, schema, providerOptions }),
103	    );
104	  }
105	
106	  private async dispatch<T>(
107	    plan: OraclePromptPlan,
108	    call: (adapter: OracleProviderAdapter, route: OracleModelRoute) => Promise<T>,
109	  ): Promise<T> {
110	    const route = this.resolveRoute(plan.routeId, plan.taskType);
111	    const adapter = this.adapters[route.provider];
112	    try {
113	      if (!adapter) throw new NoAdapterRegisteredError(route.provider);
114	      return this.withRouteMetadata(await call(adapter, route), route);
115	    } catch (err) {
116	      if (!this.fallbackOnError) throw err;
117	      if (!route.fallbackRouteId) throw err;
118	      if (!this.shouldFallback(err)) throw err;
119	      // Dispatch to fallback. Rebuild the plan with the fallback routeId so
120	      // observability records reflect which route actually ran.
121	      const fallbackPlan = { ...plan, routeId: route.fallbackRouteId };
122	      const { route: fbRoute, adapter: fbAdapter } = this.resolve(
123	        fallbackPlan.routeId,
124	        fallbackPlan.taskType,
125	      );
126	      return this.withRouteMetadata(await call(fbAdapter, fbRoute), fbRoute, route.routeId, err);
127	    }
128	  }
129	
130	  private resolveRoute(routeId: string, taskType?: OracleTaskType): OracleModelRoute {
131	    const route = getOracleRoute(routeId) ?? this.resolveDynamicRoute(routeId, taskType);
132	    if (!route) throw new UnknownRouteError(routeId);
133	    return route;
134	  }
135	
136	  private resolveDynamicRoute(
137	    routeId: string,
138	    taskType?: OracleTaskType,
139	  ): OracleModelRoute | null {
140	    if (!routeId.includes('/')) return null;
141	    const role = this.roleForTaskType(taskType);
142	    return role ? resolveModelRoute(routeId, role) : null;
143	  }
144	
145	  private roleForTaskType(taskType?: OracleTaskType): OracleModelRole | null {
146	    switch (taskType) {
147	      case 'interview_chat':
148	      case 'gap_generation':
149	        return 'interview';
150	      case 'message_claim_extraction':
151	      case 'document_claim_extraction':
152	      case 'contradiction_detection':
153	      case 'validation_repair':
154	        return 'extraction';
155	      case 'brain_synthesis':
156	        return 'synthesis';
157	      case 'admin_explanation':
158	      case 'model_capability_discovery':
159	      default:
160	        return null;
161	    }
162	  }
163	
164	  private withRouteMetadata<T>(
165	    result: T,
166	    route: OracleModelRoute,
167	    fellBackFromRouteId?: string,
168	    fallbackError?: unknown,
169	  ): T {
170	    if (!result || typeof result !== 'object') return result;
171	    return {
172	      ...(result as Record<string, unknown>),
173	      routeId: route.routeId,
174	      provider: route.provider,
175	      modelId: route.modelId,
176	      fellBackFromRouteId,
177	      fallbackReason: fallbackError ? this.fallbackReason(fallbackError) : undefined,
178	    } as T;
179	  }
180	
181	  private fallbackReason(err: unknown): string {
