183	      const msg = err.message || err.name;
184	      return msg.length > 100 ? `${msg.slice(0, 97)}...` : msg;
185	    }
186	    const msg = String(err);
187	    return msg.length > 100 ? `${msg.slice(0, 97)}...` : msg;
188	  }
189	
190	  /**
191	   * Conservative fallback policy. Falls back on:
192	   *   - provider adapter not yet implemented (R2 transitional state)
193	   *   - network/timeout errors (well-known node fetch error names)
194	   *   - explicit rate-limit / 429 markers
195	   *
196	   * Does NOT fall back on:
197	   *   - validation failures (those have their own repair flow)
198	   *   - assertion errors from ContextCompiler
199	   */
