1	/**
2	 * buildStandardAdapters() — single source of truth for the production adapter
3	 * map. Used by /api/chat and every Trigger.dev worker so that adding a new
4	 * provider only touches this file (plus the route catalog).
5	 *
6	 * Tolerant of missing env vars: if any adapter's constructor throws (e.g.
7	 * DEEPSEEK_API_KEY isn't set yet), that adapter is omitted instead of taking
8	 * down the whole map. Dispatch to an unregistered adapter still fails fast
9	 * inside ModelRouter — this only prevents one missing key from breaking
10	 * every endpoint at boot.
11	 */
12	
13	import { AnthropicAdapter } from '../providers/anthropic-adapter';
14	import { VertexGeminiAdapter } from '../providers/vertex-gemini-adapter';
15	import { GoogleGeminiAdapter } from '../providers/google-gemini-adapter';
16	import { OpenAIAdapter } from '../providers/openai-adapter';
17	import { DeepSeekAdapter } from '../providers/deepseek-adapter';
18	import { QwenAdapter } from '../providers/qwen-adapter';
19	import type { ProviderAdapterMap } from '../routing/model-router';
20	import type { OracleProvider } from '../routes';
21	import type { OracleProviderAdapter } from '../providers/types';
22	
23	function tryAdd(
24	  map: ProviderAdapterMap,
25	  key: OracleProvider,
26	  factory: () => OracleProviderAdapter,
27	): void {
28	  try {
29	    map[key] = factory();
30	  } catch (err) {
31	    // Boot stays resilient — an optional provider missing its key shouldn't crash
32	    // the worker. But NEVER silently: a skipped provider means every route that
33	    // targets it will fail "No adapter registered for provider" and fall back to
34	    // another model with no obvious cause. This was previously suppressed in prod
35	    // (`if (!IS_PROD)`), which hid that Qwen never ran in production for weeks.
36	    // eslint-disable-next-line no-console
37	    console.error(
38	      `[buildStandardAdapters] PROVIDER UNAVAILABLE: "${key}" was NOT registered ` +
39	        `(${err instanceof Error ? err.message : String(err)}). Any route targeting ` +
40	        `${key} will fail to dispatch and fall back. Set the provider's credentials to enable it.`,
41	    );
42	  }
43	}
44	
45	export function buildStandardAdapters(): ProviderAdapterMap {
46	  const map: ProviderAdapterMap = {};
47	  tryAdd(map, 'anthropic', () => new AnthropicAdapter());
48	  tryAdd(map, 'vertex',    () => new VertexGeminiAdapter());
49	  tryAdd(map, 'google',    () => new GoogleGeminiAdapter());
50	  tryAdd(map, 'openai',    () => new OpenAIAdapter());
51	  tryAdd(map, 'deepseek',  () => new DeepSeekAdapter());
52	  tryAdd(map, 'qwen',      () => new QwenAdapter());
53	  return map;
54	}
